    "HLTHPRT_PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION";
const PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_LEVEL_ENV: &str =
    "HLTHPRT_PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_LEVEL";
const PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_MIN_BYTES_ENV: &str =
    "HLTHPRT_PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_MIN_BYTES";
const PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_MIN_SAVINGS_PCT_ENV: &str =
    "HLTHPRT_PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_MIN_SAVINGS_PCT";
const DEFAULT_SERVING_BINARY_BLOCK_BYTES: usize = 2 * 1024 * 1024;
const DEFAULT_SERVING_BINARY_V3_PROVIDER_CODE_SORT_CHUNK_BYTES: usize = 128 * 1024 * 1024;
const DEFAULT_SERVING_BINARY_COMPRESSION_MIN_BYTES: usize = 128;
const DEFAULT_SERVING_BINARY_COMPRESSION_MIN_SAVINGS_PCT: f64 = 2.0;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum ServingBinaryTargetCopyFormat {
    SharedBinary,
}

impl ServingBinaryTargetCopyFormat {
    fn label(self) -> &'static str {
        "postgres_binary_shared_blocks"
    }
}

fn serving_parse_global_id_binary(field: &[u8]) -> io::Result<[u8; GLOBAL_ID_BYTES]> {
    if field.len() != GLOBAL_ID_BYTES {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "PostgreSQL binary COPY 128-bit id must contain {GLOBAL_ID_BYTES} bytes, got {}",
                field.len()
            ),
        ));
    }
    let mut out = [0u8; GLOBAL_ID_BYTES];
    out.copy_from_slice(field);
    Ok(out)
}

fn read_exact_optional<R: Read>(reader: &mut R, buffer: &mut [u8]) -> io::Result<bool> {
    let mut offset = 0usize;
    while offset < buffer.len() {
        match reader.read(&mut buffer[offset..])? {
            0 if offset == 0 => return Ok(false),
            0 => {
                return Err(io::Error::new(
                    io::ErrorKind::UnexpectedEof,
                    "unexpected EOF inside PostgreSQL binary COPY stream",
                ));
            }
            read_bytes => offset += read_bytes,
        }
    }
    Ok(true)
}

fn read_i16_be<R: Read>(reader: &mut R) -> io::Result<Option<i16>> {
    let mut buffer = [0u8; 2];
    if !read_exact_optional(reader, &mut buffer)? {
        return Ok(None);
    }
    Ok(Some(i16::from_be_bytes(buffer)))
}

fn read_i32_be<R: Read>(reader: &mut R) -> io::Result<i32> {
    let mut buffer = [0u8; 4];
    reader.read_exact(&mut buffer)?;
    Ok(i32::from_be_bytes(buffer))
}

fn read_pg_binary_copy_header<R: Read>(reader: &mut R) -> io::Result<()> {
    let mut signature = [0u8; 11];
    reader.read_exact(&mut signature)?;
    if &signature != b"PGCOPY\n\xff\r\n\0" {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "PostgreSQL binary COPY stream has an invalid header",
        ));
    }
    let _flags = read_i32_be(reader)?;
    let extension_length = read_i32_be(reader)?;
    if extension_length < 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "PostgreSQL binary COPY stream has a negative extension length",
        ));
    }
    if extension_length > 0 {
        let mut extension = vec![0u8; extension_length as usize];
        reader.read_exact(&mut extension)?;
    }
    Ok(())
}

#[cfg(test)]
fn pg_binary_i32(field: &[u8], name: &str) -> io::Result<i32> {
    if field.len() != 4 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "PostgreSQL binary COPY field {name} must be int4, got {} bytes",
                field.len()
            ),
        ));
    }
    let mut buffer = [0u8; 4];
    buffer.copy_from_slice(field);
    Ok(i32::from_be_bytes(buffer))
}

fn pg_binary_u64(field: &[u8], name: &str) -> io::Result<u64> {
    match field.len() {
        4 => {
            let mut buffer = [0u8; 4];
            buffer.copy_from_slice(field);
            let value = i32::from_be_bytes(buffer);
            if value < 0 {
                return Err(io::Error::new(
                    io::ErrorKind::InvalidData,
                    format!("PostgreSQL binary COPY field {name} cannot be negative"),
                ));
            }
            Ok(value as u64)
        }
        8 => {
            let mut buffer = [0u8; 8];
            buffer.copy_from_slice(field);
            let value = i64::from_be_bytes(buffer);
            if value < 0 {
                return Err(io::Error::new(
                    io::ErrorKind::InvalidData,
                    format!("PostgreSQL binary COPY field {name} cannot be negative"),
                ));
            }
            Ok(value as u64)
        }
        _ => Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "PostgreSQL binary COPY field {name} must be int4 or int8, got {} bytes",
                field.len()
            ),
        )),
    }
}

fn read_pg_binary_nullable_field<R: Read>(reader: &mut R) -> io::Result<Option<Vec<u8>>> {
    let field_length = read_i32_be(reader)?;
    if field_length == -1 {
        return Ok(None);
    }
    if field_length < -1 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PostgreSQL binary COPY field has invalid length {field_length}"),
        ));
    }
    let mut field = vec![0u8; field_length as usize];
    reader.read_exact(&mut field)?;
    Ok(Some(field))
}

fn read_pg_binary_copy_row<R: Read>(
    reader: &mut R,
    expected_field_count: i16,
    label: &str,
) -> io::Result<Option<Vec<Option<Vec<u8>>>>> {
    let field_count = read_i16_be(reader)?.ok_or_else(|| {
        io::Error::new(
            io::ErrorKind::UnexpectedEof,
            format!("{label} PostgreSQL binary COPY stream is missing its trailer"),
        )
    })?;
    if field_count == -1 {
        return Ok(None);
    }
    if field_count != expected_field_count {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "{label} PostgreSQL binary COPY row must have {expected_field_count} fields, got {field_count}"
            ),
        ));
    }
    (0..field_count)
        .map(|_| read_pg_binary_nullable_field(reader))
        .collect::<io::Result<Vec<_>>>()
        .map(Some)
}

fn required_pg_binary_field<'a>(
    fields: &'a [Option<Vec<u8>>],
    index: usize,
    name: &str,
) -> io::Result<&'a [u8]> {
    fields.get(index).and_then(Option::as_deref).ok_or_else(|| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PostgreSQL binary COPY field {name} cannot be NULL"),
        )
    })
}

fn pg_binary_nonnegative_i64(field: &[u8], name: &str) -> io::Result<i64> {
    let value = pg_binary_u64(field, name)?;
    i64::try_from(value).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PostgreSQL binary COPY field {name} exceeds i64"),
        )
    })
}

fn pg_binary_nonnegative_int8(field: &[u8], name: &str) -> io::Result<u64> {
    if field.len() != 8 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "PostgreSQL binary COPY field {name} must be int8, got {} bytes",
                field.len()
            ),
        ));
    }
    let value = i64::from_be_bytes(field.try_into().map_err(to_io_error)?);
    if value < 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PostgreSQL binary COPY field {name} cannot be negative"),
        ));
    }
    Ok(value as u64)
}

#[cfg(test)]
fn pg_binary_nonnegative_i32(field: &[u8], name: &str) -> io::Result<i32> {
    let value = pg_binary_nonnegative_i64(field, name)?;
    i32::try_from(value).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PostgreSQL binary COPY field {name} exceeds i32"),
        )
    })
}

fn pg_binary_optional_nonnegative_i64(field: Option<&[u8]>, name: &str) -> io::Result<Option<i64>> {
    field
        .map(|value| pg_binary_nonnegative_i64(value, name))
        .transpose()
}

fn decimal_text_field(field: &[u8]) -> Option<&str> {
    let text = std::str::from_utf8(field).ok()?;
    let unsigned = text
        .strip_prefix('-')
        .or_else(|| text.strip_prefix('+'))
        .unwrap_or(text);
    if unsigned.is_empty() {
        return None;
    }
    let mut decimal_points = 0usize;
    let mut digit_count = 0usize;
    for byte in unsigned.bytes() {
        if byte == b'.' {
            decimal_points += 1;
        } else if byte.is_ascii_digit() {
            digit_count += 1;
        } else {
            return None;
        }
    }
    (decimal_points <= 1 && digit_count > 0).then_some(text)
}

fn pg_binary_numeric_text(field: &[u8]) -> io::Result<String> {
    const NUMERIC_POS: u16 = 0x0000;
    const NUMERIC_NEG: u16 = 0x4000;

    if field.len() < 8 || !field.len().is_multiple_of(2) {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "PostgreSQL binary numeric field has an invalid byte count",
        ));
    }
    let read_i16 = |offset: usize| i16::from_be_bytes([field[offset], field[offset + 1]]);
    let digit_count = read_i16(0);
    let weight = read_i16(2);
    let sign = u16::from_be_bytes([field[4], field[5]]);
    let display_scale = read_i16(6);
    if digit_count < 0 || display_scale < 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "PostgreSQL binary numeric field has negative metadata",
        ));
    }
    let digit_count = digit_count as usize;
    let expected_bytes = digit_count
        .checked_mul(2)
        .and_then(|bytes| bytes.checked_add(8))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PostgreSQL binary numeric field length overflows usize",
            )
        })?;
    if field.len() != expected_bytes {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "PostgreSQL binary numeric digit count does not match its byte count",
        ));
    }
    if !matches!(sign, NUMERIC_POS | NUMERIC_NEG) {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "PostgreSQL binary negotiated_rate must be a finite numeric value",
        ));
    }
    let mut digits = Vec::with_capacity(digit_count);
    for digit_bytes in field[8..].chunks_exact(2) {
        let digit = u16::from_be_bytes([digit_bytes[0], digit_bytes[1]]);
        if digit > 9999 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PostgreSQL binary numeric digit exceeds base 10000",
            ));
        }
        digits.push(digit);
    }
    if digits
        .first()
        .is_some_and(|digit| *digit == 0 && digit_count > 0)
        || digits
            .last()
            .is_some_and(|digit| *digit == 0 && digit_count > 0)
    {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "PostgreSQL binary numeric field has non-canonical zero groups",
        ));
    }

    let nonzero = digits.iter().any(|digit| *digit != 0);
    let mut text = String::new();
    if sign == NUMERIC_NEG && nonzero {
        text.push('-');
    }
    if weight < 0 {
        text.push('0');
    } else {
        for group_power in (0..=i32::from(weight)).rev() {
            let digit_index = i32::from(weight) - group_power;
            let digit = usize::try_from(digit_index)
                .ok()
                .and_then(|index| digits.get(index))
                .copied()
                .unwrap_or(0);
            if group_power == i32::from(weight) {
                text.push_str(&digit.to_string());
            } else {
                text.push_str(&format!("{digit:04}"));
            }
        }
    }

    let display_scale = display_scale as usize;
    if display_scale > 0 {
        text.push('.');
        let fractional_groups = display_scale.div_ceil(4);
        let mut fractional = String::with_capacity(fractional_groups.saturating_mul(4));
        for group_offset in 1..=fractional_groups {
            let digit_index = i32::from(weight) + group_offset as i32;
            let digit = usize::try_from(digit_index)
                .ok()
                .and_then(|index| digits.get(index))
                .copied()
                .unwrap_or(0);
            fractional.push_str(&format!("{digit:04}"));
        }
        text.push_str(&fractional[..display_scale]);
    }
    Ok(text)
}

fn pg_binary_negotiated_rate(field: &[u8]) -> io::Result<String> {
    if let Some(text) = decimal_text_field(field) {
        return Ok(text.to_owned());
    }
    pg_binary_numeric_text(field)
}

mod ptg2_serving_binary_v3 {
    #[cfg(test)]
    use std::collections::{BTreeMap, BTreeSet};
    use std::io;

    pub(crate) const FORMAT_VERSION: u8 = 1;
    pub(crate) const INDEXED_FORMAT_VERSION: u8 = 2;
    pub(crate) const CHECKPOINT_INTERVAL: usize = 32;
    pub(crate) const ATOM_KEY_24_BITS: u8 = 24;
    pub(crate) const ATOM_KEY_32_BITS: u8 = 32;
    #[cfg(test)]
    pub(crate) const MAX_24_BIT_KEY_COUNT: i64 = 1 << ATOM_KEY_24_BITS;
    #[cfg(test)]
    pub(crate) const MAX_32_BIT_KEY_COUNT: i64 = 1_i64 << ATOM_KEY_32_BITS;

    const CODE_CONTAINER_SHIFT: u32 = 16;
    const CODE_CONTAINER_LOW_MASK: u64 = (1 << CODE_CONTAINER_SHIFT) - 1;
    const CODE_CONTAINER_BITMAP_BYTES: usize = 1 << (CODE_CONTAINER_SHIFT - 3);
    const CODE_CONTAINER_SPARSE: u8 = 1;
    const CODE_CONTAINER_RUNS: u8 = 2;
    const CODE_CONTAINER_BITMAP: u8 = 3;

    #[derive(Clone, Debug, Eq, PartialEq)]
    pub(crate) struct CodeSetStats {
        pub(crate) code_count: usize,
        pub(crate) container_count: usize,
        pub(crate) sparse_container_count: usize,
        pub(crate) run_container_count: usize,
        pub(crate) bitmap_container_count: usize,
        pub(crate) encoded_bytes: usize,
    }

    #[derive(Clone, Debug, Eq, PartialEq)]
    pub(crate) struct PriceAtomRecord {
        pub(crate) negotiated_rate: Option<String>,
        pub(crate) attribute_keys: Vec<Option<i64>>,
    }

    fn invalid_input(message: impl Into<String>) -> io::Error {
        io::Error::new(io::ErrorKind::InvalidInput, message.into())
    }

    #[cfg(test)]
    fn invalid_data(message: impl Into<String>) -> io::Error {
        io::Error::new(io::ErrorKind::InvalidData, message.into())
    }

    fn append_uvarint(buffer: &mut Vec<u8>, mut value: u64) {
        while value >= 0x80 {
            buffer.push((value as u8 & 0x7f) | 0x80);
            value >>= 7;
        }
        buffer.push(value as u8);
    }

    fn append_checkpoint_offset(buffer: &mut Vec<u8>, record_offset: usize) -> io::Result<()> {
        let encoded_offset = u32::try_from(record_offset)
            .map_err(|_| invalid_input("PTG2 v3 checkpoint offset exceeds uint32"))?;
        buffer.extend_from_slice(&encoded_offset.to_le_bytes());
        Ok(())
    }

    #[cfg(test)]
    fn read_uvarint(payload: &[u8], offset: usize) -> io::Result<(u64, usize)> {
        let mut value = 0u64;
        let mut shift = 0u32;
        let mut cursor = offset;
        while let Some(&current_byte) = payload.get(cursor) {
            cursor += 1;
            let low_bits = u64::from(current_byte & 0x7f);
            if shift >= 64 || low_bits > (u64::MAX >> shift) {
                return Err(invalid_data("uvarint is too large"));
            }
            value |= low_bits << shift;
            if current_byte & 0x80 == 0 {
                return Ok((value, cursor));
            }
            shift += 7;
            if shift > 63 {
                return Err(invalid_data("uvarint is too large"));
            }
        }
        Err(invalid_data("uvarint is truncated"))
    }

    #[cfg(test)]
    fn read_checkpoint_offset(payload: &[u8], cursor: usize) -> io::Result<(u32, usize)> {
        let checkpoint_end = cursor
            .checked_add(4)
            .ok_or_else(|| invalid_data("PTG2 v3 checkpoint offset overflows"))?;
        let checkpoint_bytes: [u8; 4] = payload
            .get(cursor..checkpoint_end)
            .ok_or_else(|| invalid_data("PTG2 v3 checkpoint directory is truncated"))?
            .try_into()
            .map_err(|_| invalid_data("PTG2 v3 checkpoint directory is truncated"))?;
        Ok((u32::from_le_bytes(checkpoint_bytes), checkpoint_end))
    }

    #[cfg(test)]
    fn checkpoint_shape(
        payload: &[u8],
        cursor: usize,
        entry_count: usize,
    ) -> io::Result<(usize, usize)> {
        let (checkpoint_interval, cursor) = read_uvarint(payload, cursor)?;
        let checkpoint_interval = usize::try_from(checkpoint_interval)
            .map_err(|_| invalid_data("PTG2 v3 checkpoint interval is too large"))?;
        if checkpoint_interval == 0 {
            return Err(invalid_data("PTG2 v3 checkpoint interval is invalid"));
        }
        let (checkpoint_count, cursor) = read_uvarint(payload, cursor)?;
        let checkpoint_count = usize::try_from(checkpoint_count)
            .map_err(|_| invalid_data("PTG2 v3 checkpoint count is too large"))?;
        if checkpoint_count != entry_count.div_ceil(checkpoint_interval) {
            return Err(invalid_data("PTG2 v3 checkpoint count is invalid"));
        }
        Ok((checkpoint_count, cursor))
    }

    #[cfg(test)]
    fn skip_membership_checkpoint_directory(
        payload: &[u8],
        cursor: usize,
        entry_count: usize,
    ) -> io::Result<usize> {
        let (checkpoint_count, mut cursor) = checkpoint_shape(payload, cursor, entry_count)?;
        for checkpoint_index in 0..checkpoint_count {
            let (previous_key_plus_one, next_cursor) = read_uvarint(payload, cursor)?;
            cursor = next_cursor;
            let (record_offset, next_cursor) = read_checkpoint_offset(payload, cursor)?;
            cursor = next_cursor;
            if checkpoint_index == 0 && (previous_key_plus_one != 0 || record_offset != 0) {
                return Err(invalid_data(
                    "PTG2 v3 membership checkpoint directory must start at zero",
                ));
            }
        }
        Ok(cursor)
    }

    #[cfg(test)]
    fn skip_atom_checkpoint_directory(
        payload: &[u8],
        cursor: usize,
        entry_count: usize,
    ) -> io::Result<usize> {
        let (checkpoint_count, mut cursor) = checkpoint_shape(payload, cursor, entry_count)?;
        for checkpoint_index in 0..checkpoint_count {
            let (record_offset, next_cursor) = read_checkpoint_offset(payload, cursor)?;
            cursor = next_cursor;
            if checkpoint_index == 0 && record_offset != 0 {
                return Err(invalid_data(
                    "PTG2 v3 atom checkpoint directory must start at zero",
                ));
            }
        }
        Ok(cursor)
    }

    #[cfg(test)]
    pub(crate) fn select_atom_key_bits(atom_count: i64) -> io::Result<u8> {
        if atom_count < 0 {
            return Err(invalid_input("atom_count cannot be negative"));
        }
        if atom_count <= MAX_24_BIT_KEY_COUNT {
            return Ok(ATOM_KEY_24_BITS);
        }
        if atom_count <= MAX_32_BIT_KEY_COUNT {
            return Ok(ATOM_KEY_32_BITS);
        }
        Err(invalid_input("PTG2 v3 supports at most 2^32 price atoms"))
    }

    fn dense_key_bytes(key_bits: u8) -> io::Result<usize> {
        match key_bits {
            ATOM_KEY_24_BITS => Ok(3),
            ATOM_KEY_32_BITS => Ok(4),
            _ => Err(invalid_input("PTG2 v3 dense keys must use 24 or 32 bits")),
        }
    }

    #[cfg(test)]
    fn key_bits_from_bytes(key_bytes: u8) -> io::Result<u8> {
        match key_bytes {
            3 => Ok(ATOM_KEY_24_BITS),
            4 => Ok(ATOM_KEY_32_BITS),
            _ => Err(invalid_data(
                "PTG2 v3 dense-key payload must use three or four bytes",
            )),
        }
    }

    pub(crate) fn encode_dense_keys(keys: &[i64], key_bits: u8) -> io::Result<Vec<u8>> {
        let key_bytes = dense_key_bytes(key_bits)?;
        let maximum_key = (1_u64 << key_bits) - 1;
        let mut payload = Vec::with_capacity(keys.len().saturating_mul(key_bytes));
        for &source_key in keys {
            let normalized_key = u64::try_from(source_key).map_err(|_| {
                invalid_input(format!(
                    "dense key {source_key} does not fit in {key_bits} bits"
                ))
            })?;
            if normalized_key > maximum_key {
                return Err(invalid_input(format!(
                    "dense key {source_key} does not fit in {key_bits} bits"
                )));
            }
            let encoded = normalized_key.to_le_bytes();
            payload.extend_from_slice(&encoded[..key_bytes]);
        }
        Ok(payload)
    }

    #[cfg(test)]
    pub(crate) fn decode_dense_keys(payload: &[u8], key_bits: u8) -> io::Result<Vec<u32>> {
        let key_bytes = dense_key_bytes(key_bits)?;
        if !payload.len().is_multiple_of(key_bytes) {
            return Err(invalid_data(
                "dense-key payload length is not aligned to its key width",
            ));
        }
        Ok(payload
            .chunks_exact(key_bytes)
            .map(|chunk| {
                let mut encoded = [0u8; 4];
                encoded[..key_bytes].copy_from_slice(chunk);
                u32::from_le_bytes(encoded)
            })
            .collect())
    }

    pub(crate) fn encode_price_memberships(
        memberships: &[(i64, Vec<i64>)],
        atom_key_bits: u8,
    ) -> io::Result<Vec<u8>> {
        let key_bytes = dense_key_bytes(atom_key_bits)?;
        let mut previous_price_key = None;
        for (price_key, _) in memberships {
            if *price_key < 0 {
                return Err(invalid_input("price keys cannot be negative"));
            }
            if previous_price_key.is_some_and(|previous| *price_key <= previous) {
                return Err(invalid_input(
                    "price memberships must be strictly ordered by price key",
                ));
            }
            previous_price_key = Some(*price_key);
        }

        let mut encoded_records = Vec::new();
        let mut checkpoints = Vec::new();
        let mut previous_price_key = 0i64;
        for (membership_index, (price_key, atom_keys)) in memberships.iter().enumerate() {
            if membership_index.is_multiple_of(CHECKPOINT_INTERVAL) {
                let previous_key_plus_one = if membership_index == 0 {
                    0
                } else {
                    u64::try_from(previous_price_key)
                        .ok()
                        .and_then(|value| value.checked_add(1))
                        .ok_or_else(|| invalid_input("price membership key exceeds uint64"))?
                };
                checkpoints.push((previous_key_plus_one, encoded_records.len()));
            }
            let price_delta = if membership_index == 0 {
                *price_key
            } else {
                *price_key - previous_price_key
            };
            append_uvarint(&mut encoded_records, price_delta as u64);
            append_uvarint(&mut encoded_records, atom_keys.len() as u64);
            encoded_records.extend_from_slice(&encode_dense_keys(atom_keys, atom_key_bits)?);
            previous_price_key = *price_key;
        }
        let mut encoded = vec![INDEXED_FORMAT_VERSION, key_bytes as u8];
        append_uvarint(&mut encoded, memberships.len() as u64);
        append_uvarint(&mut encoded, CHECKPOINT_INTERVAL as u64);
        append_uvarint(&mut encoded, checkpoints.len() as u64);
        for (previous_key_plus_one, record_offset) in checkpoints {
            append_uvarint(&mut encoded, previous_key_plus_one);
            append_checkpoint_offset(&mut encoded, record_offset)?;
        }
        encoded.extend_from_slice(&encoded_records);
        Ok(encoded)
    }

    #[cfg(test)]
    pub(crate) fn decode_price_memberships(payload: &[u8]) -> io::Result<BTreeMap<u64, Vec<u32>>> {
        if payload.len() < 2 || !matches!(payload[0], FORMAT_VERSION | INDEXED_FORMAT_VERSION) {
            return Err(invalid_data(
                "unsupported PTG2 v3 price-membership payload version",
            ));
        }
        let atom_key_bits = key_bits_from_bytes(payload[1])?;
        let key_bytes = dense_key_bytes(atom_key_bits)?;
        let (membership_count, mut cursor) = read_uvarint(payload, 2)?;
        let membership_count = usize::try_from(membership_count)
            .map_err(|_| invalid_data("PTG2 v3 price-membership count is too large"))?;
        if payload[0] == INDEXED_FORMAT_VERSION {
            cursor = skip_membership_checkpoint_directory(payload, cursor, membership_count)?;
        }
        if membership_count > payload.len().saturating_sub(cursor) / 2 {
            return Err(invalid_data("uvarint is truncated"));
        }

        let mut memberships_by_price_key = BTreeMap::new();
        let mut previous_price_key = 0u64;
        for membership_index in 0..membership_count {
            let (price_delta, next_cursor) = read_uvarint(payload, cursor)?;
            cursor = next_cursor;
            let price_key = if membership_index == 0 {
                price_delta
            } else {
                previous_price_key
                    .checked_add(price_delta)
                    .ok_or_else(|| invalid_data("price membership key overflows u64"))?
            };
            let (atom_count, next_cursor) = read_uvarint(payload, cursor)?;
            cursor = next_cursor;
            let atom_count = usize::try_from(atom_count)
                .map_err(|_| invalid_data("PTG2 v3 price-membership atom count is too large"))?;
            let atom_bytes = atom_count.checked_mul(key_bytes).ok_or_else(|| {
                invalid_data("PTG2 v3 price-membership atom byte count overflows")
            })?;
            let atom_end = cursor.checked_add(atom_bytes).ok_or_else(|| {
                invalid_data("PTG2 v3 price-membership atom byte count overflows")
            })?;
            if atom_end > payload.len() {
                return Err(invalid_data(
                    "PTG2 v3 price-membership atom keys are truncated",
                ));
            }
            memberships_by_price_key.insert(
                price_key,
                decode_dense_keys(&payload[cursor..atom_end], atom_key_bits)?,
            );
            cursor = atom_end;
            previous_price_key = price_key;
        }
        if cursor != payload.len() {
            return Err(invalid_data(
                "PTG2 v3 price-membership payload has trailing bytes",
            ));
        }
        Ok(memberships_by_price_key)
    }

    pub(crate) fn encode_price_atoms(price_atoms: &[PriceAtomRecord]) -> io::Result<Vec<u8>> {
        let attribute_count = price_atoms
            .first()
            .map_or(0, |price_atom| price_atom.attribute_keys.len());
        if price_atoms
            .iter()
            .any(|price_atom| price_atom.attribute_keys.len() != attribute_count)
        {
            return Err(invalid_input(
                "all PTG2 v3 price atoms must have the same attribute-key count",
            ));
        }

        let mut encoded_records = Vec::new();
        let mut checkpoint_offsets = Vec::new();
        for (atom_index, price_atom) in price_atoms.iter().enumerate() {
            if atom_index.is_multiple_of(CHECKPOINT_INTERVAL) {
                checkpoint_offsets.push(encoded_records.len());
            }
            append_optional_text(&mut encoded_records, price_atom.negotiated_rate.as_deref())?;
            for attribute_key in &price_atom.attribute_keys {
                let encoded_key = match attribute_key {
                    None => 0,
                    Some(key) => u64::try_from(*key)
                        .ok()
                        .and_then(|value| value.checked_add(1))
                        .ok_or_else(|| invalid_input("uvarint cannot encode negative values"))?,
                };
                append_uvarint(&mut encoded_records, encoded_key);
            }
        }
        let mut encoded = vec![INDEXED_FORMAT_VERSION];
        append_uvarint(&mut encoded, attribute_count as u64);
        append_uvarint(&mut encoded, price_atoms.len() as u64);
        append_uvarint(&mut encoded, CHECKPOINT_INTERVAL as u64);
        append_uvarint(&mut encoded, checkpoint_offsets.len() as u64);
        for checkpoint_offset in checkpoint_offsets {
            append_checkpoint_offset(&mut encoded, checkpoint_offset)?;
        }
        encoded.extend_from_slice(&encoded_records);
        Ok(encoded)
    }

    #[cfg(test)]
    pub(crate) fn decode_price_atoms(payload: &[u8]) -> io::Result<Vec<PriceAtomRecord>> {
        if !matches!(
            payload.first(),
            Some(&FORMAT_VERSION | &INDEXED_FORMAT_VERSION)
        ) {
            return Err(invalid_data(
                "unsupported PTG2 v3 price-atom payload version",
            ));
        }
        let (attribute_count, mut cursor) = read_uvarint(payload, 1)?;
        let attribute_count = usize::try_from(attribute_count)
            .map_err(|_| invalid_data("PTG2 v3 price-atom attribute count is too large"))?;
        let (atom_count, next_cursor) = read_uvarint(payload, cursor)?;
        cursor = next_cursor;
        let atom_count = usize::try_from(atom_count)
            .map_err(|_| invalid_data("PTG2 v3 price-atom count is too large"))?;
        if payload[0] == INDEXED_FORMAT_VERSION {
            cursor = skip_atom_checkpoint_directory(payload, cursor, atom_count)?;
        }
        let minimum_atom_bytes = attribute_count
            .checked_add(1)
            .and_then(|bytes| bytes.checked_mul(atom_count))
            .ok_or_else(|| invalid_data("PTG2 v3 price-atom counts overflow"))?;
        if minimum_atom_bytes > payload.len().saturating_sub(cursor) {
            return Err(invalid_data("PTG2 v3 price-atom payload is truncated"));
        }

        let mut price_atoms = Vec::with_capacity(atom_count);
        for _ in 0..atom_count {
            let (negotiated_rate, next_cursor) = read_optional_text(payload, cursor)?;
            cursor = next_cursor;
            let mut attribute_keys = Vec::with_capacity(attribute_count);
            for _ in 0..attribute_count {
                let (encoded_key, next_cursor) = read_uvarint(payload, cursor)?;
                cursor = next_cursor;
                let attribute_key = if encoded_key == 0 {
                    None
                } else {
                    Some(i64::try_from(encoded_key - 1).map_err(|_| {
                        invalid_data("PTG2 v3 price-atom attribute key exceeds i64")
                    })?)
                };
                attribute_keys.push(attribute_key);
            }
            price_atoms.push(PriceAtomRecord {
                negotiated_rate,
                attribute_keys,
            });
        }
        if cursor != payload.len() {
            return Err(invalid_data(
                "PTG2 v3 price-atom payload has trailing bytes",
            ));
        }
        Ok(price_atoms)
    }

    fn append_optional_text(buffer: &mut Vec<u8>, text_value: Option<&str>) -> io::Result<()> {
        let Some(text_value) = text_value else {
            append_uvarint(buffer, 0);
            return Ok(());
        };
        let encoded_length = text_value
            .len()
            .checked_add(1)
            .and_then(|length| u64::try_from(length).ok())
            .ok_or_else(|| invalid_input("PTG2 v3 price-atom text is too large"))?;
        append_uvarint(buffer, encoded_length);
        buffer.extend_from_slice(text_value.as_bytes());
        Ok(())
    }

    #[cfg(test)]
    fn read_optional_text(payload: &[u8], offset: usize) -> io::Result<(Option<String>, usize)> {
        let (encoded_length, cursor) = read_uvarint(payload, offset)?;
        if encoded_length == 0 {
            return Ok((None, cursor));
        }
        let text_bytes = usize::try_from(encoded_length - 1)
            .map_err(|_| invalid_data("PTG2 v3 price-atom text is too large"))?;
        let text_end = cursor
            .checked_add(text_bytes)
            .ok_or_else(|| invalid_data("PTG2 v3 price-atom text length overflows"))?;
        if text_end > payload.len() {
            return Err(invalid_data("PTG2 v3 price-atom text is truncated"));
        }
        let text = std::str::from_utf8(&payload[cursor..text_end])
            .map_err(|_| invalid_data("PTG2 v3 price-atom text is not valid UTF-8"))?;
        Ok((Some(text.to_owned()), text_end))
    }

    #[cfg(test)]
    pub(crate) fn encode_provider_code_set(
        code_keys: &[i64],
    ) -> io::Result<(Vec<u8>, CodeSetStats)> {
        let normalized_keys = normalized_code_keys(code_keys)?;
        let containers = code_containers(&normalized_keys);
        let mut encoded = vec![FORMAT_VERSION];
        append_uvarint(&mut encoded, containers.len() as u64);
        let mut previous_high = 0u16;
        let mut stats = CodeSetStats {
            code_count: normalized_keys.len(),
            container_count: containers.len(),
            sparse_container_count: 0,
            run_container_count: 0,
            bitmap_container_count: 0,
            encoded_bytes: 0,
        };
        for (container_index, (high_bits, low_keys)) in containers.iter().enumerate() {
            let (kind, body) = smallest_code_container(low_keys);
            let high_delta = if container_index == 0 {
                *high_bits
            } else {
                *high_bits - previous_high
            };
            append_uvarint(&mut encoded, u64::from(high_delta));
            encoded.push(kind);
            append_uvarint(&mut encoded, low_keys.len() as u64);
            append_uvarint(&mut encoded, body.len() as u64);
            encoded.extend_from_slice(&body);
            previous_high = *high_bits;
            match kind {
                CODE_CONTAINER_SPARSE => stats.sparse_container_count += 1,
                CODE_CONTAINER_RUNS => stats.run_container_count += 1,
                CODE_CONTAINER_BITMAP => stats.bitmap_container_count += 1,
                _ => unreachable!(),
            }
        }
        stats.encoded_bytes = encoded.len();
        Ok((encoded, stats))
    }

    pub(crate) fn encode_sorted_provider_code_set(
        code_keys: &[i64],
    ) -> io::Result<(Vec<u8>, CodeSetStats)> {
        if code_keys.first().is_some_and(|key| *key < 0)
            || code_keys
                .last()
                .is_some_and(|key| *key > i64::from(i32::MAX))
        {
            return Err(invalid_input(
                "sorted provider code keys must fit in nonnegative signed PostgreSQL integers",
            ));
        }
        if code_keys.windows(2).any(|keys| keys[0] >= keys[1]) {
            return Err(invalid_input(
                "sorted provider code keys must be strictly ordered",
            ));
        }
        let container_count = code_keys
            .iter()
            .map(|key| (*key as u32 >> CODE_CONTAINER_SHIFT) as u16)
            .fold((None, 0usize), |(previous, count), high_bits| {
                if previous == Some(high_bits) {
                    (previous, count)
                } else {
                    (Some(high_bits), count.saturating_add(1))
                }
            })
            .1;
        let mut encoded = vec![FORMAT_VERSION];
        append_uvarint(&mut encoded, container_count as u64);
        let mut previous_high = 0u16;
        let mut container_index = 0usize;
        let mut code_index = 0usize;
        let mut stats = CodeSetStats {
            code_count: code_keys.len(),
            container_count,
            sparse_container_count: 0,
            run_container_count: 0,
            bitmap_container_count: 0,
            encoded_bytes: 0,
        };
        while code_index < code_keys.len() {
            let high_bits = (code_keys[code_index] as u32 >> CODE_CONTAINER_SHIFT) as u16;
            let container_start = code_index;
            while code_index < code_keys.len()
                && (code_keys[code_index] as u32 >> CODE_CONTAINER_SHIFT) as u16 == high_bits
            {
                code_index += 1;
            }
            let low_keys = code_keys[container_start..code_index]
                .iter()
                .map(|key| (*key as u32 & CODE_CONTAINER_LOW_MASK as u32) as u16)
                .collect::<Vec<_>>();
            let (kind, body) = smallest_code_container(&low_keys);
            let high_delta = if container_index == 0 {
                high_bits
            } else {
                high_bits - previous_high
            };
            append_uvarint(&mut encoded, u64::from(high_delta));
            encoded.push(kind);
            append_uvarint(&mut encoded, low_keys.len() as u64);
            append_uvarint(&mut encoded, body.len() as u64);
            encoded.extend_from_slice(&body);
            match kind {
                CODE_CONTAINER_SPARSE => stats.sparse_container_count += 1,
                CODE_CONTAINER_RUNS => stats.run_container_count += 1,
                CODE_CONTAINER_BITMAP => stats.bitmap_container_count += 1,
                _ => unreachable!(),
            }
            previous_high = high_bits;
            container_index += 1;
        }
        stats.encoded_bytes = encoded.len();
        Ok((encoded, stats))
    }

    #[cfg(test)]
    pub(crate) fn decode_provider_code_set(payload: &[u8]) -> io::Result<Vec<u64>> {
        if payload.first() != Some(&FORMAT_VERSION) {
            return Err(invalid_data(
                "unsupported PTG2 v3 provider-code payload version",
            ));
        }
        let (container_count, mut cursor) = read_uvarint(payload, 1)?;
        let container_count = usize::try_from(container_count)
            .map_err(|_| invalid_data("provider-code container count is too large"))?;
        if container_count > payload.len().saturating_sub(cursor) / 4 {
            return Err(invalid_data("provider-code container is truncated"));
        }

        let mut code_keys = Vec::new();
        let mut previous_high = 0u64;
        for container_index in 0..container_count {
            let (high_delta, next_cursor) = read_uvarint(payload, cursor)?;
            cursor = next_cursor;
            let high_bits = if container_index == 0 {
                high_delta
            } else {
                previous_high
                    .checked_add(high_delta)
                    .ok_or_else(|| invalid_data("provider-code high key overflows u64"))?
            };
            let container_kind = *payload
                .get(cursor)
                .ok_or_else(|| invalid_data("provider-code container kind is truncated"))?;
            cursor += 1;
            let (cardinality, next_cursor) = read_uvarint(payload, cursor)?;
            cursor = next_cursor;
            let cardinality = usize::try_from(cardinality)
                .map_err(|_| invalid_data("provider-code cardinality is too large"))?;
            let (body_bytes, next_cursor) = read_uvarint(payload, cursor)?;
            cursor = next_cursor;
            let body_bytes = usize::try_from(body_bytes)
                .map_err(|_| invalid_data("provider-code body byte count is too large"))?;
            let body_end = cursor
                .checked_add(body_bytes)
                .ok_or_else(|| invalid_data("provider-code body byte count overflows"))?;
            if body_end > payload.len() {
                return Err(invalid_data("provider-code container body is truncated"));
            }
            let low_keys =
                decode_code_container(container_kind, &payload[cursor..body_end], cardinality)?;
            if high_bits > (u64::MAX >> CODE_CONTAINER_SHIFT) {
                return Err(invalid_data("provider-code key overflows u64"));
            }
            let high_prefix = high_bits << CODE_CONTAINER_SHIFT;
            code_keys.extend(low_keys.into_iter().map(|low_key| high_prefix | low_key));
            cursor = body_end;
            previous_high = high_bits;
        }
        if cursor != payload.len() {
            return Err(invalid_data("provider-code payload has trailing bytes"));
        }
        if code_keys.windows(2).any(|keys| keys[0] >= keys[1]) {
            return Err(invalid_data(
                "provider-code payload is not strictly ordered",
            ));
        }
        Ok(code_keys)
    }

    #[cfg(test)]
    fn normalized_code_keys(code_keys: &[i64]) -> io::Result<Vec<u32>> {
        let normalized_keys: BTreeSet<i64> = code_keys.iter().copied().collect();
        if normalized_keys.first().is_some_and(|key| *key < 0) {
            return Err(invalid_input("code keys cannot be negative"));
        }
        if normalized_keys
            .last()
            .is_some_and(|key| *key > i64::from(i32::MAX))
        {
            return Err(invalid_input(
                "code keys must fit in signed PostgreSQL integer keys",
            ));
        }
        normalized_keys
            .into_iter()
            .map(|key| u32::try_from(key).map_err(|error| invalid_input(error.to_string())))
            .collect()
    }

    #[cfg(test)]
    fn code_containers(code_keys: &[u32]) -> Vec<(u16, Vec<u16>)> {
        let mut containers: BTreeMap<u16, Vec<u16>> = BTreeMap::new();
        for &code_key in code_keys {
            containers
                .entry((code_key >> CODE_CONTAINER_SHIFT) as u16)
                .or_default()
                .push((u64::from(code_key) & CODE_CONTAINER_LOW_MASK) as u16);
        }
        containers.into_iter().collect()
    }

    fn smallest_code_container(low_keys: &[u16]) -> (u8, Vec<u8>) {
        let candidates = [
            (
                CODE_CONTAINER_SPARSE,
                encode_sparse_code_container(low_keys),
            ),
            (CODE_CONTAINER_RUNS, encode_run_code_container(low_keys)),
            (
                CODE_CONTAINER_BITMAP,
                encode_bitmap_code_container(low_keys),
            ),
        ];
        candidates
            .into_iter()
            .min_by_key(|(kind, body)| (body.len(), *kind))
            .expect("provider-code container candidates are non-empty")
    }

    fn encode_sparse_code_container(low_keys: &[u16]) -> Vec<u8> {
        let mut payload = Vec::new();
        let mut previous_low = 0u16;
        for (key_index, &low_key) in low_keys.iter().enumerate() {
            let encoded_low = if key_index == 0 {
                low_key
            } else {
                low_key - previous_low
            };
            append_uvarint(&mut payload, u64::from(encoded_low));
            previous_low = low_key;
        }
        payload
    }

    fn encode_run_code_container(low_keys: &[u16]) -> Vec<u8> {
        let runs = code_runs(low_keys);
        let mut payload = Vec::new();
        append_uvarint(&mut payload, runs.len() as u64);
        let mut previous_end = -1i64;
        for (run_start, run_end) in runs {
            append_uvarint(
                &mut payload,
                i64::from(run_start) as u64 - (previous_end + 1) as u64,
            );
            append_uvarint(&mut payload, u64::from(run_end - run_start));
            previous_end = i64::from(run_end);
        }
        payload
    }

    fn code_runs(low_keys: &[u16]) -> Vec<(u16, u16)> {
        let Some(&first_key) = low_keys.first() else {
            return Vec::new();
        };
        let mut runs = Vec::new();
        let mut run_start = first_key;
        let mut run_end = first_key;
        for &low_key in &low_keys[1..] {
            if run_end.checked_add(1) == Some(low_key) {
                run_end = low_key;
            } else {
                runs.push((run_start, run_end));
                run_start = low_key;
                run_end = low_key;
            }
        }
        runs.push((run_start, run_end));
        runs
    }

    fn encode_bitmap_code_container(low_keys: &[u16]) -> Vec<u8> {
        let mut payload = vec![0u8; CODE_CONTAINER_BITMAP_BYTES];
        for &low_key in low_keys {
            let low_key = usize::from(low_key);
            payload[low_key >> 3] |= 1 << (low_key & 7);
        }
        payload
    }

    #[cfg(test)]
    fn decode_code_container(
        container_kind: u8,
        body: &[u8],
        cardinality: usize,
    ) -> io::Result<Vec<u64>> {
        let low_keys = match container_kind {
            CODE_CONTAINER_SPARSE => decode_sparse_code_container(body, cardinality)?,
            CODE_CONTAINER_RUNS => decode_run_code_container(body)?,
            CODE_CONTAINER_BITMAP => decode_bitmap_code_container(body)?,
            _ => {
                return Err(invalid_data(format!(
                    "unknown provider-code container kind: {container_kind}"
                )));
            }
        };
        if low_keys.len() != cardinality {
            return Err(invalid_data(
                "provider-code container cardinality does not match its payload",
            ));
        }
        Ok(low_keys)
    }

    #[cfg(test)]
    fn decode_sparse_code_container(body: &[u8], cardinality: usize) -> io::Result<Vec<u64>> {
        if cardinality > body.len() {
            return Err(invalid_data("uvarint is truncated"));
        }
        let mut low_keys = Vec::with_capacity(cardinality);
        let mut cursor = 0usize;
        let mut previous_low = 0u64;
        for key_index in 0..cardinality {
            let (encoded_low, next_cursor) = read_uvarint(body, cursor)?;
            cursor = next_cursor;
            let low_key = if key_index == 0 {
                encoded_low
            } else {
                previous_low
                    .checked_add(encoded_low)
                    .ok_or_else(|| invalid_data("sparse provider-code key overflows u64"))?
            };
            if low_key > CODE_CONTAINER_LOW_MASK {
                return Err(invalid_data(
                    "sparse provider-code key exceeds its 16-bit container",
                ));
            }
            low_keys.push(low_key);
            previous_low = low_key;
        }
        if cursor != body.len() {
            return Err(invalid_data(
                "sparse provider-code container has trailing bytes",
            ));
        }
        Ok(low_keys)
    }

    #[cfg(test)]
    fn decode_run_code_container(body: &[u8]) -> io::Result<Vec<u64>> {
        let (run_count, mut cursor) = read_uvarint(body, 0)?;
        let run_count = usize::try_from(run_count)
            .map_err(|_| invalid_data("run provider-code count is too large"))?;
        if run_count > body.len().saturating_sub(cursor) / 2 {
            return Err(invalid_data("uvarint is truncated"));
        }
        let mut low_keys = Vec::new();
        let mut previous_end = None;
        for _ in 0..run_count {
            let (start_delta, next_cursor) = read_uvarint(body, cursor)?;
            cursor = next_cursor;
            let (run_length, next_cursor) = read_uvarint(body, cursor)?;
            cursor = next_cursor;
            let next_available = previous_end.map_or(0u64, |end: u64| end + 1);
            let run_start = next_available
                .checked_add(start_delta)
                .ok_or_else(|| invalid_data("run provider-code key overflows u64"))?;
            let run_end = run_start
                .checked_add(run_length)
                .ok_or_else(|| invalid_data("run provider-code key overflows u64"))?;
            if run_end > CODE_CONTAINER_LOW_MASK {
                return Err(invalid_data(
                    "run provider-code key exceeds its 16-bit container",
                ));
            }
            low_keys.extend(run_start..=run_end);
            previous_end = Some(run_end);
        }
        if cursor != body.len() {
            return Err(invalid_data(
                "run provider-code container has trailing bytes",
            ));
        }
        Ok(low_keys)
    }

    #[cfg(test)]
    fn decode_bitmap_code_container(body: &[u8]) -> io::Result<Vec<u64>> {
        if body.len() != CODE_CONTAINER_BITMAP_BYTES {
            return Err(invalid_data(
                "bitmap provider-code container has an invalid byte count",
            ));
        }
        let mut low_keys = Vec::new();
        for (byte_index, &current_byte) in body.iter().enumerate() {
            for bit_index in 0..8 {
                if current_byte & (1 << bit_index) != 0 {
                    low_keys.push((byte_index * 8 + bit_index) as u64);
                }
            }
        }
        Ok(low_keys)
    }

    #[cfg(test)]
    mod tests {
        use super::*;

        fn price_atoms_fixture() -> Vec<PriceAtomRecord> {
            vec![
                PriceAtomRecord {
                    negotiated_rate: Some("15.25".to_string()),
                    attribute_keys: vec![Some(0), None, Some(2), Some(3), Some(4), Some(5), None],
                },
                PriceAtomRecord {
                    negotiated_rate: None,
                    attribute_keys: vec![
                        Some(1),
                        Some(8),
                        Some(13),
                        None,
                        Some(21),
                        Some(34),
                        Some(55),
                    ],
                },
            ]
        }

        #[test]
        fn dense_keys_match_python_goldens_and_boundaries() {
            let keys = [0, 1, 255, 65_535, (1 << 24) - 1];
            let expected_24 = [
                0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0xff, 0x00, 0x00, 0xff, 0xff, 0x00, 0xff, 0xff,
                0xff,
            ];
            assert_eq!(encode_dense_keys(&keys, 24).unwrap(), expected_24);
            assert_eq!(
                decode_dense_keys(&expected_24, 24).unwrap(),
                keys.map(|key| key as u32)
            );

            let keys_32 = [0, 1, 255, 65_535, u32::MAX as i64];
            let expected_32 = [
                0x00, 0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x00, 0xff, 0x00, 0x00, 0x00, 0xff, 0xff,
                0x00, 0x00, 0xff, 0xff, 0xff, 0xff,
            ];
            assert_eq!(encode_dense_keys(&keys_32, 32).unwrap(), expected_32);
            assert_eq!(
                decode_dense_keys(&expected_32, 32).unwrap(),
                keys_32.map(|key| key as u32)
            );
            assert_eq!(select_atom_key_bits(0).unwrap(), 24);
            assert_eq!(select_atom_key_bits(1 << 24).unwrap(), 24);
            assert_eq!(select_atom_key_bits((1 << 24) + 1).unwrap(), 32);
            assert!(select_atom_key_bits(-1).is_err());
            assert!(select_atom_key_bits((1_i64 << 32) + 1).is_err());
            assert!(encode_dense_keys(&[1 << 24], 24).is_err());
            assert!(decode_dense_keys(&[0, 1], 24).is_err());
            assert!(encode_dense_keys(&[], 16).is_err());
        }

        #[test]
        fn price_memberships_match_python_goldens_and_round_trip() {
            let memberships = vec![(3, vec![0, 1, 257]), (9, vec![65_535])];
            let expected_24 = [
                0x02, 0x03, 0x02, 0x20, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x03, 0x03, 0x00, 0x00,
                0x00, 0x01, 0x00, 0x00, 0x01, 0x01, 0x00, 0x06, 0x01, 0xff, 0xff, 0x00,
            ];
            let expected_32 = [
                0x02, 0x04, 0x02, 0x20, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x03, 0x03, 0x00, 0x00,
                0x00, 0x00, 0x01, 0x00, 0x00, 0x00, 0x01, 0x01, 0x00, 0x00, 0x06, 0x01, 0xff, 0xff,
                0x00, 0x00,
            ];
            assert_eq!(
                encode_price_memberships(&memberships, 24).unwrap(),
                expected_24
            );
            assert_eq!(
                encode_price_memberships(&memberships, 32).unwrap(),
                expected_32
            );
            let expected = BTreeMap::from([(3, vec![0, 1, 257]), (9, vec![65_535])]);
            assert_eq!(decode_price_memberships(&expected_24).unwrap(), expected);
            assert_eq!(decode_price_memberships(&expected_32).unwrap(), expected);

            let duplicate_membership = vec![(3, vec![1, 1, 257])];
            let duplicate_payload = encode_price_memberships(&duplicate_membership, 24).unwrap();
            assert_eq!(
                decode_price_memberships(&duplicate_payload).unwrap(),
                BTreeMap::from([(3, vec![1, 1, 257])])
            );
        }

        #[test]
        fn price_memberships_reject_invalid_order_and_corruption() {
            assert!(encode_price_memberships(&[(2, vec![1]), (2, vec![3])], 24).is_err());
            assert!(encode_price_memberships(&[(-1, vec![1])], 24).is_err());
            assert!(decode_price_memberships(&[2, 3, 0]).is_err());
            assert!(decode_price_memberships(&[1, 2, 0]).is_err());
            assert!(decode_price_memberships(&[1, 3, 1, 0, 1, 0, 0]).is_err());

            let mut trailing = encode_price_memberships(&[(0, vec![])], 24).unwrap();
            trailing.push(0);
            assert!(decode_price_memberships(&trailing).is_err());
            assert!(read_uvarint(&[0x80; 10], 0).is_err());
            let mut oversized = vec![0xff; 9];
            oversized.push(0x02);
            assert!(read_uvarint(&oversized, 0).is_err());
            let mut maximum = Vec::new();
            append_uvarint(&mut maximum, u64::MAX);
            assert_eq!(read_uvarint(&maximum, 0).unwrap().0, u64::MAX);
        }

        #[test]
        fn price_atoms_match_python_golden_and_round_trip() {
            let expected = [
                0x02, 0x07, 0x02, 0x20, 0x01, 0x00, 0x00, 0x00, 0x00, 0x06, 0x31, 0x35, 0x2e, 0x32,
                0x35, 0x01, 0x00, 0x03, 0x04, 0x05, 0x06, 0x00, 0x00, 0x02, 0x09, 0x0e, 0x00, 0x16,
                0x23, 0x38,
            ];
            let atoms = price_atoms_fixture();
            assert_eq!(encode_price_atoms(&atoms).unwrap(), expected);
            assert_eq!(decode_price_atoms(&expected).unwrap(), atoms);

            let unicode = vec![PriceAtomRecord {
                negotiated_rate: Some("12.50 EUR".to_string()),
                attribute_keys: vec![],
            }];
            assert_eq!(
                decode_price_atoms(&encode_price_atoms(&unicode).unwrap()).unwrap(),
                unicode
            );
        }

        #[test]
        fn price_atoms_reject_shape_and_payload_corruption() {
            let mismatched = vec![
                PriceAtomRecord {
                    negotiated_rate: None,
                    attribute_keys: vec![Some(1)],
                },
                PriceAtomRecord {
                    negotiated_rate: None,
                    attribute_keys: vec![],
                },
            ];
            assert!(encode_price_atoms(&mismatched).is_err());
            assert!(encode_price_atoms(&[PriceAtomRecord {
                negotiated_rate: None,
                attribute_keys: vec![Some(-2)],
            }])
            .is_err());
            assert!(encode_price_atoms(&[PriceAtomRecord {
                negotiated_rate: None,
                attribute_keys: vec![Some(-1)],
            }])
            .is_err());
            assert!(decode_price_atoms(&[1, 0, 1, 3, b'1']).is_err());
            assert!(decode_price_atoms(&[1, 0, 1, 2, 0xff]).is_err());

            let mut trailing = encode_price_atoms(&price_atoms_fixture()).unwrap();
            trailing.push(0);
            assert!(decode_price_atoms(&trailing).is_err());
        }

        #[test]
        fn provider_code_set_matches_python_golden() {
            let source = [1, 9, 65_000, 65_536, 65_537, 65_538, 65_539, 65_540];
            let expected = [
                0x01, 0x02, 0x00, 0x01, 0x03, 0x05, 0x01, 0x08, 0xdf, 0xfb, 0x03, 0x01, 0x02, 0x05,
                0x03, 0x01, 0x00, 0x04,
            ];
            let (encoded, stats) = encode_provider_code_set(&source).unwrap();
            assert_eq!(encoded, expected);
            assert_eq!(
                decode_provider_code_set(&expected).unwrap(),
                source.map(|key| key as u64)
            );
            assert_eq!(stats.code_count, source.len());
            assert_eq!(stats.container_count, 2);
            assert_eq!(stats.sparse_container_count, 1);
            assert_eq!(stats.run_container_count, 1);
            assert_eq!(stats.bitmap_container_count, 0);
            assert_eq!(stats.encoded_bytes, expected.len());
        }

        #[test]
        fn provider_code_set_selects_all_container_modes_and_round_trips() {
            let mut source = vec![1, 9, 65_000];
            source.extend(65_536..69_536);
            source.extend((0..=65_534).step_by(2).map(|low| 131_072 + low));
            source.reverse();
            source.push(1);

            let (encoded, stats) = encode_provider_code_set(&source).unwrap();
            let mut expected = source.clone();
            expected.sort_unstable();
            expected.dedup();
            let (sorted_encoded, sorted_stats) =
                encode_sorted_provider_code_set(&expected).unwrap();
            assert_eq!(sorted_encoded, encoded);
            assert_eq!(sorted_stats, stats);
            assert_eq!(
                decode_provider_code_set(&encoded).unwrap(),
                expected
                    .into_iter()
                    .map(|key| key as u64)
                    .collect::<Vec<_>>()
            );
            assert_eq!(stats.code_count, 36_771);
            assert_eq!(stats.container_count, 3);
            assert_eq!(stats.sparse_container_count, 1);
            assert_eq!(stats.run_container_count, 1);
            assert_eq!(stats.bitmap_container_count, 1);
            assert_eq!(stats.encoded_bytes, encoded.len());

            let empty = encode_provider_code_set(&[]).unwrap();
            assert_eq!(empty.0, [1, 0]);
            assert_eq!(
                decode_provider_code_set(&empty.0).unwrap(),
                Vec::<u64>::new()
            );
        }

        #[test]
        fn provider_code_set_rejects_boundaries_and_corruption() {
            assert!(encode_provider_code_set(&[-1]).is_err());
            assert!(encode_provider_code_set(&[i64::from(i32::MAX) + 1]).is_err());
            assert!(encode_sorted_provider_code_set(&[2, 1]).is_err());
            assert!(encode_sorted_provider_code_set(&[1, 1]).is_err());

            let valid = encode_provider_code_set(&(0..100).collect::<Vec<_>>())
                .unwrap()
                .0;
            assert!(decode_provider_code_set(&valid[..valid.len() - 1]).is_err());
            assert!(decode_provider_code_set(&[2, 0]).is_err());
            assert!(decode_provider_code_set(&[1, 1, 0, 9, 0, 0]).is_err());
            assert!(decode_provider_code_set(&[1, 1, 0, 1, 2, 1, 1]).is_err());
            assert!(decode_provider_code_set(&[1, 1, 0, 3, 0, 1, 0]).is_err());

            let mut trailing = encode_provider_code_set(&[1, 2]).unwrap().0;
            trailing.push(0);
            assert!(decode_provider_code_set(&trailing).is_err());
        }
    }
}

fn write_uvarint_to_vec(out: &mut Vec<u8>, value: u64) {
    let mut encoded = value;
    loop {
        let byte = (encoded & 0x7f) as u8;
        encoded >>= 7;
        if encoded == 0 {
            out.push(byte);
            break;
        }
        out.push(byte | 0x80);
    }
}

fn uvarint_encoded_len(value: u64) -> usize {
    let significant_bits = 64usize.saturating_sub(value.leading_zeros() as usize);
    significant_bits.max(1).div_ceil(7)
}

fn serving_binary_block_bytes() -> usize {
    env_usize(
        PTG2_SERVING_BINARY_BLOCK_BYTES_ENV,
        DEFAULT_SERVING_BINARY_BLOCK_BYTES,
    )
    .max(64 * 1024)
}

fn serving_binary_v3_provider_code_sort_chunk_bytes() -> usize {
    env_usize(
        PTG2_SERVING_BINARY_V3_PROVIDER_CODE_SORT_CHUNK_BYTES_ENV,
        DEFAULT_SERVING_BINARY_V3_PROVIDER_CODE_SORT_CHUNK_BYTES,
    )
    .max(8)
}

fn serving_binary_payload_compression() -> String {
    let value = env::var(PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_ENV)
        .unwrap_or_else(|_| "zlib".to_string())
        .trim()
        .to_ascii_lowercase();
    if value == "none" || value == "zlib" {
        value
    } else {
        "zlib".to_string()
    }
}

fn serving_binary_payload_compression_level() -> u32 {
    env::var(PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_LEVEL_ENV)
        .ok()
        .and_then(|value| value.parse::<u32>().ok())
        .unwrap_or(6)
        .min(9)
}

fn serving_binary_payload_compression_min_bytes() -> usize {
    env_usize(
        PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_MIN_BYTES_ENV,
        DEFAULT_SERVING_BINARY_COMPRESSION_MIN_BYTES,
    )
}

fn serving_binary_payload_compression_min_savings_pct() -> f64 {
    env::var(PTG2_SERVING_BINARY_PAYLOAD_COMPRESSION_MIN_SAVINGS_PCT_ENV)
        .ok()
        .and_then(|value| value.parse::<f64>().ok())
        .filter(|value| value.is_finite())
        .unwrap_or(DEFAULT_SERVING_BINARY_COMPRESSION_MIN_SAVINGS_PCT)
        .clamp(0.0, 100.0)
}

#[derive(Clone, Copy, Debug, PartialEq)]
struct ServingBinaryCompressionOptions {
    enabled: bool,
    level: u32,
    minimum_bytes: usize,
    minimum_savings_pct: f64,
}

impl ServingBinaryCompressionOptions {
    fn configured() -> Self {
        Self {
            enabled: serving_binary_payload_compression() == "zlib",
            level: serving_binary_payload_compression_level(),
            minimum_bytes: serving_binary_payload_compression_min_bytes(),
            minimum_savings_pct: serving_binary_payload_compression_min_savings_pct(),
        }
    }
}

fn serving_binary_compression_is_worthwhile(
    raw_bytes: usize,
    compressed_bytes: usize,
    minimum_savings_pct: f64,
) -> bool {
    if compressed_bytes >= raw_bytes || raw_bytes == 0 {
        return false;
    }
    let saved_bytes = raw_bytes - compressed_bytes;
    (saved_bytes as f64 * 100.0) >= (raw_bytes as f64 * minimum_savings_pct)
}

fn serving_binary_i32_count(value: usize, name: &str) -> io::Result<i32> {
    i32::try_from(value).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PTG2 serving binary {name} exceeds PostgreSQL integer range"),
        )
    })
}

fn write_pg_binary_copy_header<W: Write>(writer: &mut W) -> io::Result<()> {
    writer.write_all(b"PGCOPY\n\xff\r\n\0")?;
    writer.write_all(&0i32.to_be_bytes())?;
    writer.write_all(&0i32.to_be_bytes())
}

fn write_pg_binary_copy_trailer<W: Write>(writer: &mut W) -> io::Result<()> {
    writer.write_all(&(-1i16).to_be_bytes())
}

fn write_pg_binary_copy_field<W: Write>(writer: &mut W, field: &[u8]) -> io::Result<()> {
    let field_len = i32::try_from(field.len()).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "PostgreSQL binary COPY field exceeds int32 length",
        )
    })?;
    writer.write_all(&field_len.to_be_bytes())?;
    writer.write_all(field)
}

fn write_pg_binary_copy_i32_field<W: Write>(writer: &mut W, value: i32) -> io::Result<()> {
    write_pg_binary_copy_field(writer, &value.to_be_bytes())
}

fn write_pg_binary_copy_i16_field<W: Write>(writer: &mut W, value: i16) -> io::Result<()> {
    write_pg_binary_copy_field(writer, &value.to_be_bytes())
}

fn write_pg_binary_copy_i64_field<W: Write>(writer: &mut W, value: i64) -> io::Result<()> {
    write_pg_binary_copy_field(writer, &value.to_be_bytes())
}

fn write_serving_binary_copy_header<W: Write>(
    writer: &mut W,
    _target_format: ServingBinaryTargetCopyFormat,
) -> io::Result<()> {
    write_pg_binary_copy_header(writer)
}

fn write_serving_binary_copy_trailer<W: SharedBlockCopyWriter>(
    writer: &mut W,
    _target_format: ServingBinaryTargetCopyFormat,
) -> io::Result<()> {
    writer.flush_shared_block_preparation()?;
    write_pg_binary_copy_trailer(writer)
}

struct CountingWriter<W: Write> {
    inner: W,
    byte_count: u64,
    sha256: Sha256,
    shared_blocks: SharedBlockCopySummary,
    shared_block_compression: ServingBinaryCompressionOptions,
    shared_block_batch_limits: Option<SharedBlockPreparationBatchLimits>,
    pending_shared_blocks: Vec<PendingSharedBlockCopyRecord>,
    pending_shared_block_raw_bytes: usize,
    recycled_shared_block_payloads: Vec<Vec<u8>>,
    recycled_shared_block_capacity_bytes: usize,
    shared_block_preparation_metrics: SharedBlockPreparationMetrics,
}

impl<W: Write> CountingWriter<W> {
    fn new(inner: W) -> Self {
        Self {
            inner,
            byte_count: 0,
            sha256: Sha256::new(),
            shared_blocks: SharedBlockCopySummary::default(),
            shared_block_compression: ServingBinaryCompressionOptions::configured(),
            shared_block_batch_limits: None,
            pending_shared_blocks: Vec::new(),
            pending_shared_block_raw_bytes: 0,
            recycled_shared_block_payloads: Vec::new(),
            recycled_shared_block_capacity_bytes: 0,
            shared_block_preparation_metrics: SharedBlockPreparationMetrics::default(),
        }
    }

    fn with_shared_block_preparation_batch(
        inner: W,
        limits: SharedBlockPreparationBatchLimits,
    ) -> io::Result<Self> {
        limits.validate()?;
        let mut writer = Self::new(inner);
        writer.shared_block_batch_limits = Some(limits);
        writer.pending_shared_blocks = Vec::with_capacity(limits.maximum_records);
        writer
            .shared_block_preparation_metrics
            .configured_maximum_records = Some(limits.maximum_records);
        writer
            .shared_block_preparation_metrics
            .configured_maximum_raw_bytes = Some(limits.maximum_raw_bytes);
        Ok(writer)
    }

    fn byte_count(&self) -> u64 {
        self.byte_count
    }

    fn shared_block_summary(&self, path: &Path) -> Value {
        self.shared_blocks.to_json(
            path,
            self.byte_count,
            sha256_hex(&self.sha256.clone().finalize()),
        )
    }

    fn shared_block_preparation_summary(&self) -> Value {
        self.shared_block_preparation_metrics.to_json()
    }

    fn hydrate_shared_block_stats(
        &self,
        artifact_kind: &str,
        stats: &mut ServingBinaryV3BlockStats,
    ) -> io::Result<()> {
        stats.hydrate_storage(
            artifact_kind,
            self.shared_blocks
                .artifact_storage
                .get(artifact_kind)
                .copied()
                .unwrap_or_default(),
        )
    }
}

impl<W: Write> Write for CountingWriter<W> {
    fn write(&mut self, buf: &[u8]) -> io::Result<usize> {
        let written = self.inner.write(buf)?;
        self.byte_count = self.byte_count.saturating_add(written as u64);
        self.sha256.update(&buf[..written]);
        Ok(written)
    }

    fn flush(&mut self) -> io::Result<()> {
        self.inner.flush()
    }
}

struct SharedBlockCopyRecord<'a> {
    block_hash: &'a [u8; 32],
    object_kind: &'a str,
    block_key: i64,
    fragment_no: i32,
    entry_count: u64,
    raw_payload_bytes: u64,
    stored_payload_bytes: u64,
    compressed: bool,
}

#[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
struct SharedBlockArtifactStorage {
    record_count: u64,
    raw_payload_bytes: u64,
    stored_payload_bytes: u64,
    compressed_records: u64,
}

struct SharedBlockCopySummary {
    row_count: u64,
    entry_count: u64,
    raw_payload_bytes: u64,
    stored_payload_bytes: u64,
    artifact_record_counts: BTreeMap<String, u64>,
    artifact_storage: BTreeMap<String, SharedBlockArtifactStorage>,
    block_hash_digest: Sha256,
}

impl Default for SharedBlockCopySummary {
    fn default() -> Self {
        let mut block_hash_digest = Sha256::new();
        block_hash_digest.update(b"PTG2V3FINALBLOCKS\x01");
        Self {
            row_count: 0,
            entry_count: 0,
            raw_payload_bytes: 0,
            stored_payload_bytes: 0,
            artifact_record_counts: BTreeMap::new(),
            artifact_storage: BTreeMap::new(),
            block_hash_digest,
        }
    }
}

impl SharedBlockCopySummary {
    fn record(&mut self, record: SharedBlockCopyRecord<'_>) -> io::Result<()> {
        self.block_hash_digest.update(record.block_hash);
        update_sha256_length_prefixed(&mut self.block_hash_digest, record.object_kind.as_bytes())?;
        self.block_hash_digest
            .update(record.block_key.to_be_bytes());
        self.block_hash_digest
            .update(record.fragment_no.to_be_bytes());
        self.block_hash_digest
            .update(record.entry_count.to_be_bytes());
        *self
            .artifact_record_counts
            .entry(record.object_kind.to_owned())
            .or_insert(0) += 1;
        let artifact_storage = self
            .artifact_storage
            .entry(record.object_kind.to_owned())
            .or_default();
        artifact_storage.record_count = artifact_storage.record_count.saturating_add(1);
        artifact_storage.raw_payload_bytes = artifact_storage
            .raw_payload_bytes
            .saturating_add(record.raw_payload_bytes);
        artifact_storage.stored_payload_bytes = artifact_storage
            .stored_payload_bytes
            .saturating_add(record.stored_payload_bytes);
        artifact_storage.compressed_records = artifact_storage
            .compressed_records
            .saturating_add(u64::from(record.compressed));
        self.row_count = self.row_count.saturating_add(1);
        self.entry_count = self.entry_count.saturating_add(record.entry_count);
        self.raw_payload_bytes = self
            .raw_payload_bytes
            .saturating_add(record.raw_payload_bytes);
        self.stored_payload_bytes = self
            .stored_payload_bytes
            .saturating_add(record.stored_payload_bytes);
        Ok(())
    }

    fn to_json(&self, path: &Path, copy_bytes: u64, copy_sha256: String) -> Value {
        json!({
            "path": path.file_name().and_then(|value| value.to_str()).unwrap_or_default(),
            "copy_format": "postgresql_binary_copy",
            "field_count": 10,
            "fields": ["block_hash", "format_version", "object_kind", "block_key", "fragment_no", "entry_count", "codec", "raw_byte_count", "stored_byte_count", "payload"],
            "mapping_identity_fields": ["object_kind", "block_key", "fragment_no", "entry_count", "block_hash"],
            "snapshot_key_included": false,
            "copy_bytes": copy_bytes,
            "copy_sha256": copy_sha256,
            "row_count": self.row_count,
            "entry_count": self.entry_count,
            "raw_payload_bytes": self.raw_payload_bytes,
            "stored_payload_bytes": self.stored_payload_bytes,
            "block_hash_digest": sha256_hex(&self.block_hash_digest.clone().finalize()),
            "artifact_record_counts": self.artifact_record_counts,
        })
    }
}

const V3_FINALIZER_SHARED_BLOCK_BATCH_MAX_RAW_BYTES: usize = 16 * 1024 * 1024;
const V3_FINALIZER_SHARED_BLOCK_BATCH_MAX_RECORDS: usize = 4096;
const V3_FINALIZER_SHARED_BLOCK_BATCH_MEMORY_MULTIPLIER: usize = 3;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct SharedBlockPreparationBatchLimits {
    maximum_raw_bytes: usize,
    maximum_records: usize,
}

impl SharedBlockPreparationBatchLimits {
    const fn finalizer_default() -> Self {
        Self {
            maximum_raw_bytes: V3_FINALIZER_SHARED_BLOCK_BATCH_MAX_RAW_BYTES,
            maximum_records: V3_FINALIZER_SHARED_BLOCK_BATCH_MAX_RECORDS,
        }
    }

    fn validate(self) -> io::Result<()> {
        if self.maximum_raw_bytes == 0 || self.maximum_records == 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                "shared-block preparation batch limits must be positive",
            ));
        }
        Ok(())
    }
}

struct PendingSharedBlockCopyRecord {
    object_kind: &'static str,
    block_key: i64,
    fragment_no: i32,
    entry_count: i64,
    raw_payload_bytes: i64,
    payload: Vec<u8>,
}

impl PendingSharedBlockCopyRecord {
    fn new(
        object_kind: &'static str,
        block_key: i64,
        fragment_no: usize,
        entry_count: usize,
        payload: Vec<u8>,
    ) -> io::Result<Self> {
        if block_key < 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                "shared block key cannot be negative",
            ));
        }
        if object_kind.trim().is_empty() {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                "shared block kind is required",
            ));
        }
        Ok(Self {
            object_kind,
            block_key,
            fragment_no: serving_binary_i32_count(fragment_no, "block_no")?,
            entry_count: i64::from(serving_binary_i32_count(entry_count, "entry_count")?),
            raw_payload_bytes: i64::try_from(payload.len()).map_err(|_| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "shared block raw payload exceeds i64",
                )
            })?,
            payload,
        })
    }
}

struct PreparedSharedBlockCopyRecord {
    object_kind: &'static str,
    block_key: i64,
    fragment_no: i32,
    entry_count: i64,
    raw_payload_bytes: i64,
    stored_payload_bytes: i64,
    payload_compression: &'static str,
    stored_payload: Vec<u8>,
    recycled_payload: Option<Vec<u8>>,
    block_hash: [u8; 32],
    preparation_seconds: f64,
}

fn prepare_shared_block_copy_record(
    pending: PendingSharedBlockCopyRecord,
    compression: ServingBinaryCompressionOptions,
) -> io::Result<PreparedSharedBlockCopyRecord> {
    let started_at = Instant::now();
    let raw_payload_bytes = pending.payload.len();
    let (stored_payload, recycled_payload, payload_compression) =
        if compression.enabled && raw_payload_bytes >= compression.minimum_bytes {
            let mut encoder = ZlibEncoder::new(
                Vec::with_capacity(raw_payload_bytes),
                Compression::new(compression.level),
            );
            encoder.write_all(&pending.payload)?;
            let compressed = encoder.finish()?;
            if serving_binary_compression_is_worthwhile(
                raw_payload_bytes,
                compressed.len(),
                compression.minimum_savings_pct,
            ) {
                (compressed, Some(pending.payload), "zlib")
            } else {
                drop(compressed);
                (pending.payload, None, "none")
            }
        } else {
            (pending.payload, None, "none")
        };
    let stored_payload_bytes = i64::try_from(stored_payload.len()).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "shared block stored payload exceeds i64",
        )
    })?;
    let block_hash = shared_v3_block_hash(
        PTG2_V3_SHARED_BLOCK_FORMAT_VERSION,
        pending.object_kind,
        payload_compression,
        &stored_payload,
    )?;
    Ok(PreparedSharedBlockCopyRecord {
        object_kind: pending.object_kind,
        block_key: pending.block_key,
        fragment_no: pending.fragment_no,
        entry_count: pending.entry_count,
        raw_payload_bytes: pending.raw_payload_bytes,
        stored_payload_bytes,
        payload_compression,
        stored_payload,
        recycled_payload,
        block_hash,
        preparation_seconds: started_at.elapsed().as_secs_f64(),
    })
}

#[derive(Clone, Copy, Debug, Default, PartialEq)]
struct SharedBlockArtifactPreparationMetrics {
    record_count: u64,
    raw_payload_bytes: u64,
    worker_seconds: f64,
}

#[derive(Debug, Default)]
struct SharedBlockPreparationMetrics {
    batch_count: u64,
    parallel_batch_count: u64,
    record_count: u64,
    raw_payload_bytes: u64,
    wall_seconds: f64,
    peak_batch_records: usize,
    peak_batch_raw_bytes: usize,
    maximum_record_raw_bytes: usize,
    configured_maximum_records: Option<usize>,
    configured_maximum_raw_bytes: Option<usize>,
    artifacts: BTreeMap<String, SharedBlockArtifactPreparationMetrics>,
}

impl SharedBlockPreparationMetrics {
    fn to_json(&self) -> Value {
        let artifacts = self
            .artifacts
            .iter()
            .map(|(kind, metrics)| {
                (
                    kind.clone(),
                    json!({
                        "record_count": metrics.record_count,
                        "raw_payload_bytes": metrics.raw_payload_bytes,
                        "worker_seconds": metrics.worker_seconds,
                    }),
                )
            })
            .collect::<serde_json::Map<String, Value>>();
        json!({
            "batch_count": self.batch_count,
            "parallel_batch_count": self.parallel_batch_count,
            "record_count": self.record_count,
            "raw_payload_bytes": self.raw_payload_bytes,
            "wall_seconds": self.wall_seconds,
            "peak_batch_records": self.peak_batch_records,
            "peak_batch_raw_bytes": self.peak_batch_raw_bytes,
            "maximum_record_raw_bytes": self.maximum_record_raw_bytes,
            "batching_enabled": self.configured_maximum_records.is_some(),
            "configured_maximum_records": self.configured_maximum_records,
            "configured_maximum_raw_bytes": self.configured_maximum_raw_bytes,
            "artifacts": artifacts,
        })
    }
}

trait SharedBlockCopyWriter: Write {
    fn record_shared_block(&mut self, record: SharedBlockCopyRecord<'_>) -> io::Result<()>;
    fn enqueue_shared_block(
        &mut self,
        object_kind: &'static str,
        block_key: i64,
        fragment_no: usize,
        entry_count: usize,
        payload: &[u8],
    ) -> io::Result<()>;
    fn flush_shared_block_preparation(&mut self) -> io::Result<()>;
}

impl<W: Write> SharedBlockCopyWriter for CountingWriter<W> {
    fn record_shared_block(&mut self, record: SharedBlockCopyRecord<'_>) -> io::Result<()> {
        self.shared_blocks.record(record)
    }

    fn enqueue_shared_block(
        &mut self,
        object_kind: &'static str,
        block_key: i64,
        fragment_no: usize,
        entry_count: usize,
        payload: &[u8],
    ) -> io::Result<()> {
        self.enqueue_shared_block_copy_record(
            object_kind,
            block_key,
            fragment_no,
            entry_count,
            payload,
        )
    }

    fn flush_shared_block_preparation(&mut self) -> io::Result<()> {
        self.flush_pending_shared_block_copy_records()
    }
}

impl<W: Write> CountingWriter<W> {
    fn take_shared_block_payload_buffer(&mut self, payload_bytes: usize) -> Vec<u8> {
        let mut buffer = self
            .recycled_shared_block_payloads
            .pop()
            .unwrap_or_default();
        self.recycled_shared_block_capacity_bytes = self
            .recycled_shared_block_capacity_bytes
            .saturating_sub(buffer.capacity());
        buffer.clear();
        if buffer.capacity() < payload_bytes {
            buffer.reserve(payload_bytes);
        }
        buffer
    }

    fn recycle_shared_block_payload_buffer(&mut self, mut buffer: Vec<u8>) {
        let Some(limits) = self.shared_block_batch_limits else {
            return;
        };
        let maximum_pool_capacity = limits.maximum_raw_bytes;
        let maximum_pool_records = limits.maximum_records;
        buffer.clear();
        if self.recycled_shared_block_payloads.len() >= maximum_pool_records
            || self
                .recycled_shared_block_capacity_bytes
                .saturating_add(buffer.capacity())
                > maximum_pool_capacity
        {
            return;
        }
        self.recycled_shared_block_capacity_bytes = self
            .recycled_shared_block_capacity_bytes
            .saturating_add(buffer.capacity());
        self.recycled_shared_block_payloads.push(buffer);
    }

    fn enqueue_shared_block_copy_record(
        &mut self,
        object_kind: &'static str,
        block_key: i64,
        fragment_no: usize,
        entry_count: usize,
        payload: &[u8],
    ) -> io::Result<()> {
        let Some(limits) = self.shared_block_batch_limits else {
            let pending = PendingSharedBlockCopyRecord::new(
                object_kind,
                block_key,
                fragment_no,
                entry_count,
                payload.to_vec(),
            )?;
            self.shared_block_preparation_metrics.peak_batch_records = self
                .shared_block_preparation_metrics
                .peak_batch_records
                .max(1);
            self.shared_block_preparation_metrics.peak_batch_raw_bytes = self
                .shared_block_preparation_metrics
                .peak_batch_raw_bytes
                .max(payload.len());
            self.shared_block_preparation_metrics
                .maximum_record_raw_bytes = self
                .shared_block_preparation_metrics
                .maximum_record_raw_bytes
                .max(payload.len());
            let prepared =
                prepare_shared_block_copy_record(pending, self.shared_block_compression)?;
            self.shared_block_preparation_metrics.batch_count = self
                .shared_block_preparation_metrics
                .batch_count
                .saturating_add(1);
            self.write_prepared_shared_block_copy_record(prepared)?;
            return Ok(());
        };

        let next_raw_bytes = self
            .pending_shared_block_raw_bytes
            .checked_add(payload.len())
            .ok_or_else(|| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "shared-block preparation batch byte count overflows usize",
                )
            })?;
        if !self.pending_shared_blocks.is_empty()
            && (self.pending_shared_blocks.len() >= limits.maximum_records
                || next_raw_bytes > limits.maximum_raw_bytes)
        {
            self.flush_pending_shared_block_copy_records()?;
        }

        let mut owned_payload = self.take_shared_block_payload_buffer(payload.len());
        owned_payload.extend_from_slice(payload);
        let pending = PendingSharedBlockCopyRecord::new(
            object_kind,
            block_key,
            fragment_no,
            entry_count,
            owned_payload,
        )?;
        self.pending_shared_block_raw_bytes = self
            .pending_shared_block_raw_bytes
            .checked_add(payload.len())
            .ok_or_else(|| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "shared-block preparation batch byte count overflows usize",
                )
            })?;
        self.pending_shared_blocks.push(pending);
        self.shared_block_preparation_metrics.peak_batch_records = self
            .shared_block_preparation_metrics
            .peak_batch_records
            .max(self.pending_shared_blocks.len());
        self.shared_block_preparation_metrics.peak_batch_raw_bytes = self
            .shared_block_preparation_metrics
            .peak_batch_raw_bytes
            .max(self.pending_shared_block_raw_bytes);
        self.shared_block_preparation_metrics
            .maximum_record_raw_bytes = self
            .shared_block_preparation_metrics
            .maximum_record_raw_bytes
            .max(payload.len());
        if self.pending_shared_blocks.len() >= limits.maximum_records
            || self.pending_shared_block_raw_bytes >= limits.maximum_raw_bytes
        {
            self.flush_pending_shared_block_copy_records()?;
        }
        Ok(())
    }

    fn flush_pending_shared_block_copy_records(&mut self) -> io::Result<()> {
        if self.pending_shared_blocks.is_empty() {
            return Ok(());
        }
        let pending = std::mem::take(&mut self.pending_shared_blocks);
        let batch_raw_bytes = std::mem::take(&mut self.pending_shared_block_raw_bytes);
        self.recycled_shared_block_payloads.clear();
        self.recycled_shared_block_capacity_bytes = 0;
        let parallel = pending.len() > 1 && rayon::current_num_threads() > 1;
        let compression = self.shared_block_compression;
        let started_at = Instant::now();
        let prepared = if parallel {
            pending
                .into_par_iter()
                .map(|record| prepare_shared_block_copy_record(record, compression))
                .collect::<io::Result<Vec<_>>>()
        } else {
            pending
                .into_iter()
                .map(|record| prepare_shared_block_copy_record(record, compression))
                .collect::<io::Result<Vec<_>>>()
        }?;
        self.shared_block_preparation_metrics.batch_count = self
            .shared_block_preparation_metrics
            .batch_count
            .saturating_add(1);
        self.shared_block_preparation_metrics.parallel_batch_count = self
            .shared_block_preparation_metrics
            .parallel_batch_count
            .saturating_add(u64::from(parallel));
        self.shared_block_preparation_metrics.wall_seconds += started_at.elapsed().as_secs_f64();
        debug_assert_eq!(
            prepared
                .iter()
                .map(|record| record.raw_payload_bytes as usize)
                .sum::<usize>(),
            batch_raw_bytes,
        );
        for record in prepared {
            self.write_prepared_shared_block_copy_record(record)?;
        }
        Ok(())
    }

    fn write_prepared_shared_block_copy_record(
        &mut self,
        prepared: PreparedSharedBlockCopyRecord,
    ) -> io::Result<()> {
        let PreparedSharedBlockCopyRecord {
            object_kind,
            block_key,
            fragment_no,
            entry_count,
            raw_payload_bytes,
            stored_payload_bytes,
            payload_compression,
            stored_payload,
            recycled_payload,
            block_hash,
            preparation_seconds,
        } = prepared;
        self.write_all(&10i16.to_be_bytes())?;
        write_pg_binary_copy_field(self, &block_hash)?;
        write_pg_binary_copy_i16_field(self, PTG2_V3_SHARED_BLOCK_FORMAT_VERSION)?;
        write_pg_binary_copy_field(self, object_kind.as_bytes())?;
        write_pg_binary_copy_i64_field(self, block_key)?;
        write_pg_binary_copy_i32_field(self, fragment_no)?;
        write_pg_binary_copy_i64_field(self, entry_count)?;
        write_pg_binary_copy_field(self, payload_compression.as_bytes())?;
        write_pg_binary_copy_i64_field(self, raw_payload_bytes)?;
        write_pg_binary_copy_i64_field(self, stored_payload_bytes)?;
        write_pg_binary_copy_field(self, &stored_payload)?;
        self.record_shared_block(SharedBlockCopyRecord {
            block_hash: &block_hash,
            object_kind,
            block_key,
            fragment_no,
            entry_count: u64::try_from(entry_count).map_err(|_| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "shared block entry count cannot be negative",
                )
            })?,
            raw_payload_bytes: u64::try_from(raw_payload_bytes).map_err(|_| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "shared block raw payload cannot be negative",
                )
            })?,
            stored_payload_bytes: u64::try_from(stored_payload_bytes).map_err(|_| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "shared block stored payload cannot be negative",
                )
            })?,
            compressed: payload_compression != "none",
        })?;
        self.shared_block_preparation_metrics.record_count = self
            .shared_block_preparation_metrics
            .record_count
            .saturating_add(1);
        self.shared_block_preparation_metrics.raw_payload_bytes = self
            .shared_block_preparation_metrics
            .raw_payload_bytes
            .saturating_add(raw_payload_bytes as u64);
        let artifact_metrics = self
            .shared_block_preparation_metrics
            .artifacts
            .entry(object_kind.to_owned())
            .or_default();
        artifact_metrics.record_count = artifact_metrics.record_count.saturating_add(1);
        artifact_metrics.raw_payload_bytes = artifact_metrics
            .raw_payload_bytes
            .saturating_add(raw_payload_bytes as u64);
        artifact_metrics.worker_seconds += preparation_seconds;
        if let Some(payload) = recycled_payload {
            self.recycle_shared_block_payload_buffer(payload);
        } else {
            self.recycle_shared_block_payload_buffer(stored_payload);
        }
        Ok(())
    }
}

const PTG2_V3_SHARED_BLOCK_FORMAT_VERSION: i16 = 2;
const PTG2_V3_SHARED_BLOCK_HASH_DOMAIN: &[u8] = b"PTG2V3BLOCK\x01";

fn update_sha256_length_prefixed(hasher: &mut Sha256, value: &[u8]) -> io::Result<()> {
    let length = u32::try_from(value.len()).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "shared block hash field exceeds u32 length",
        )
    })?;
    hasher.update(length.to_be_bytes());
    hasher.update(value);
    Ok(())
}

fn shared_v3_block_hash(
    format_version: i16,
    object_kind: &str,
    codec: &str,
    payload: &[u8],
) -> io::Result<[u8; 32]> {
    if !(1..=i16::MAX).contains(&format_version) {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "shared block format version is out of range",
        ));
    }
    let object_kind = object_kind.trim();
    let codec = codec.trim().to_ascii_lowercase();
    if object_kind.is_empty() || codec.is_empty() {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "shared block kind and codec are required",
        ));
    }
    let mut hasher = Sha256::new();
    hasher.update(PTG2_V3_SHARED_BLOCK_HASH_DOMAIN);
    hasher.update(format_version.to_be_bytes());
    update_sha256_length_prefixed(&mut hasher, object_kind.as_bytes())?;
    update_sha256_length_prefixed(&mut hasher, codec.as_bytes())?;
    update_sha256_length_prefixed(&mut hasher, payload)?;
    Ok(hasher.finalize().into())
}

fn write_serving_binary_copy_record_with_stats<W: SharedBlockCopyWriter>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    kind: &'static str,
    block_key: i32,
    block_no: usize,
    entry_count: usize,
    payload: &[u8],
) -> io::Result<()> {
    write_serving_binary_copy_record_with_i64_key_and_stats(
        writer,
        target_format,
        kind,
        i64::from(block_key),
        block_no,
        entry_count,
        payload,
    )
}

fn write_serving_binary_copy_record_with_i64_key_and_stats<W: SharedBlockCopyWriter>(
    writer: &mut W,
    _target_format: ServingBinaryTargetCopyFormat,
    kind: &'static str,
    block_key: i64,
    block_no: usize,
    entry_count: usize,
    payload: &[u8],
) -> io::Result<()> {
    writer.enqueue_shared_block(kind, block_key, block_no, entry_count, payload)
}

#[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
struct ServingBinaryV3BlockStats {
    logical_block_count: u64,
    copy_record_count: u64,
    entry_count: u64,
    stored_payload_bytes: u64,
    raw_payload_bytes: u64,
    compressed_records: u64,
}

impl ServingBinaryV3BlockStats {
    fn record_queued_payload(&mut self, raw_payload_bytes: usize) {
        self.copy_record_count = self.copy_record_count.saturating_add(1);
        self.raw_payload_bytes = self
            .raw_payload_bytes
            .saturating_add(raw_payload_bytes as u64);
    }

    fn hydrate_storage(
        &mut self,
        artifact_kind: &str,
        storage: SharedBlockArtifactStorage,
    ) -> io::Result<()> {
        if self.copy_record_count != storage.record_count
            || self.raw_payload_bytes != storage.raw_payload_bytes
        {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                format!(
                    "PTG2 v3 {artifact_kind} deferred block accounting mismatch: expected {} records/{} raw bytes, prepared {} records/{} raw bytes",
                    self.copy_record_count,
                    self.raw_payload_bytes,
                    storage.record_count,
                    storage.raw_payload_bytes,
                ),
            ));
        }
        self.stored_payload_bytes = storage.stored_payload_bytes;
        self.compressed_records = storage.compressed_records;
        Ok(())
    }

    fn storage_summary(&self) -> Value {
        json!({
            "record_count": self.copy_record_count,
            "entry_count": self.entry_count,
            "stored_payload_bytes": self.stored_payload_bytes,
            "raw_payload_bytes": self.raw_payload_bytes,
            "compressed_records": self.compressed_records,
            "compressed_saved_bytes": self.raw_payload_bytes.saturating_sub(self.stored_payload_bytes),
        })
    }
}

struct ServingBinaryV3LogicalBlock<'a> {
    artifact_kind: &'static str,
    block_key: i32,
    entry_count: usize,
    payload: &'a [u8],
}

fn write_serving_binary_v3_logical_block<W: SharedBlockCopyWriter>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    logical_block: ServingBinaryV3LogicalBlock<'_>,
    stats: &mut ServingBinaryV3BlockStats,
) -> io::Result<()> {
    if max_payload_bytes == 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "PTG2 v3 block byte limit must be positive",
        ));
    }
    if logical_block.payload.is_empty() {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "PTG2 v3 {} cannot emit an empty logical block",
                logical_block.artifact_kind
            ),
        ));
    }
    for (block_no, payload_fragment) in logical_block.payload.chunks(max_payload_bytes).enumerate()
    {
        write_serving_binary_copy_record_with_stats(
            writer,
            target_format,
            logical_block.artifact_kind,
            logical_block.block_key,
            block_no,
            if block_no == 0 {
                logical_block.entry_count
            } else {
                0
            },
            payload_fragment,
        )?;
        stats.record_queued_payload(payload_fragment.len());
    }
    stats.logical_block_count = stats.logical_block_count.saturating_add(1);
    stats.entry_count = stats
        .entry_count
        .saturating_add(logical_block.entry_count as u64);
    Ok(())
}

struct ServingBinaryV3SpoolBlock<'a> {
    artifact_kind: &'static str,
    block_key: i32,
    entry_count: usize,
    prefix: &'a [u8],
    spool_bytes: u64,
}

fn write_serving_binary_v3_spooled_logical_block<W: SharedBlockCopyWriter, R: Read + Seek>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    logical_block: ServingBinaryV3SpoolBlock<'_>,
    spool: &mut R,
    stats: &mut ServingBinaryV3BlockStats,
) -> io::Result<u64> {
    if max_payload_bytes == 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "PTG2 v3 block byte limit must be positive",
        ));
    }
    let total_payload_bytes = u64::try_from(logical_block.prefix.len())
        .ok()
        .and_then(|prefix_bytes| prefix_bytes.checked_add(logical_block.spool_bytes))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 spooled logical block byte count overflows u64",
            )
        })?;
    if total_payload_bytes == 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "PTG2 v3 {} cannot emit an empty logical block",
                logical_block.artifact_kind
            ),
        ));
    }
    spool.seek(SeekFrom::Start(0))?;
    let mut prefix_offset = 0usize;
    let mut remaining_spool_bytes = logical_block.spool_bytes;
    let mut fragment = Vec::with_capacity(max_payload_bytes.min(1024 * 1024));
    let mut block_no = 0usize;
    while prefix_offset < logical_block.prefix.len() || remaining_spool_bytes > 0 {
        fragment.clear();
        let prefix_bytes = (logical_block.prefix.len() - prefix_offset).min(max_payload_bytes);
        fragment
            .extend_from_slice(&logical_block.prefix[prefix_offset..prefix_offset + prefix_bytes]);
        prefix_offset += prefix_bytes;
        let available = max_payload_bytes - fragment.len();
        let spool_fragment_bytes = usize::try_from(remaining_spool_bytes.min(available as u64))
            .map_err(|_| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "PTG2 v3 spool fragment byte count exceeds usize",
                )
            })?;
        if spool_fragment_bytes > 0 {
            let prior_length = fragment.len();
            fragment.resize(prior_length + spool_fragment_bytes, 0);
            spool.read_exact(&mut fragment[prior_length..])?;
            remaining_spool_bytes -= spool_fragment_bytes as u64;
        }
        write_serving_binary_copy_record_with_stats(
            writer,
            target_format,
            logical_block.artifact_kind,
            logical_block.block_key,
            block_no,
            if block_no == 0 {
                logical_block.entry_count
            } else {
                0
            },
            &fragment,
        )?;
        stats.record_queued_payload(fragment.len());
        block_no = block_no.checked_add(1).ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 spool fragment number overflows usize",
            )
        })?;
    }
    stats.logical_block_count = stats.logical_block_count.saturating_add(1);
    stats.entry_count = stats
        .entry_count
        .saturating_add(logical_block.entry_count as u64);
    Ok(logical_block.spool_bytes)
}

fn serving_binary_v3_block_key(source_key: i64, block_span: i64, name: &str) -> io::Result<i32> {
    if source_key < 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PTG2 v3 {name} cannot be negative"),
        ));
    }
    i32::try_from(source_key / block_span).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PTG2 v3 {name} block key exceeds PostgreSQL integer range"),
        )
    })
}

fn serving_binary_v3_atom_key_bits(value: &str) -> io::Result<u8> {
    match value {
        "24" => Ok(ptg2_serving_binary_v3::ATOM_KEY_24_BITS),
        "32" => Ok(ptg2_serving_binary_v3::ATOM_KEY_32_BITS),
        _ => Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "PTG2 v3 atom key width must be 24 or 32 bits",
        )),
    }
}

#[cfg(test)]
fn serving_binary_v3_configured_atom_key_bits(options: &[String]) -> io::Result<u8> {
    if options.len() > 1 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "PTG2 v3 accepts at most one positional atom key width",
        ));
    }
    if let Some(value) = options.first() {
        return serving_binary_v3_atom_key_bits(value);
    }
    if let Ok(value) = env::var(PTG2_SERVING_BINARY_V3_ATOM_KEY_BITS_ENV) {
        return serving_binary_v3_atom_key_bits(value.trim());
    }
    if let Ok(value) = env::var(PTG2_SERVING_BINARY_V3_ATOM_COUNT_ENV) {
        let atom_count = value.trim().parse::<i64>().map_err(|error| {
            io::Error::new(
                io::ErrorKind::InvalidInput,
                format!("invalid PTG2 v3 atom count: {error}"),
            )
        })?;
        return ptg2_serving_binary_v3::select_atom_key_bits(atom_count);
    }
    Err(io::Error::new(
        io::ErrorKind::InvalidInput,
        format!(
            "PTG2 v3 atom key width requires <24|32>, {PTG2_SERVING_BINARY_V3_ATOM_KEY_BITS_ENV}, or {PTG2_SERVING_BINARY_V3_ATOM_COUNT_ENV}"
        ),
    ))
}

fn serving_binary_v3_validate_atom_key(atom_key: i64, atom_key_bits: u8) -> io::Result<()> {
    if !matches!(
        atom_key_bits,
        ptg2_serving_binary_v3::ATOM_KEY_24_BITS | ptg2_serving_binary_v3::ATOM_KEY_32_BITS
    ) {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "PTG2 v3 atom key width must be 24 or 32 bits",
        ));
    }
    let maximum_key = (1_u64 << atom_key_bits) - 1;
    let normalized_key = u64::try_from(atom_key).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "PTG2 v3 atom_key cannot be negative",
        )
    })?;
    if normalized_key > maximum_key {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!("PTG2 v3 atom_key {atom_key} does not fit in {atom_key_bits} bits"),
        ));
    }
    Ok(())
}

fn serving_binary_v3_spill_directory() -> io::Result<PathBuf> {
    let base_directory = env::var_os("HLTHPRT_PTG2_MANIFEST_SPILL_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(env::temp_dir);
    std::fs::create_dir_all(&base_directory)?;
    Ok(base_directory)
}

struct ServingBinaryV3ProviderCodeState {
    max_payload_bytes: usize,
    maximum_code_keys: Option<usize>,
    previous_pair: Option<(i64, i64)>,
    current_provider_key: Option<i64>,
    current_code_keys: Vec<i64>,
    current_block_key: Option<i32>,
    block_spool: File,
    block_spool_bytes: u64,
    block_provider_count: usize,
    block_stats: ServingBinaryV3BlockStats,
    row_count: u64,
    duplicate_pair_count: u64,
    code_count: u64,
    provider_set_count: u64,
    container_count: u64,
    sparse_container_count: u64,
    run_container_count: u64,
    bitmap_container_count: u64,
    maximum_code_keys_buffered: usize,
    scratch_bytes_read: u64,
    scratch_bytes_written: u64,
}

impl ServingBinaryV3ProviderCodeState {
    fn new(max_payload_bytes: usize, maximum_code_keys: Option<usize>) -> io::Result<Self> {
        if max_payload_bytes == 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                "provider-code payload limit must be positive",
            ));
        }
        Ok(Self {
            max_payload_bytes,
            maximum_code_keys,
            previous_pair: None,
            current_provider_key: None,
            current_code_keys: Vec::new(),
            current_block_key: None,
            block_spool: tempfile::tempfile_in(serving_binary_v3_spill_directory()?)?,
            block_spool_bytes: 0,
            block_provider_count: 0,
            block_stats: ServingBinaryV3BlockStats::default(),
            row_count: 0,
            duplicate_pair_count: 0,
            code_count: 0,
            provider_set_count: 0,
            container_count: 0,
            sparse_container_count: 0,
            run_container_count: 0,
            bitmap_container_count: 0,
            maximum_code_keys_buffered: 0,
            scratch_bytes_read: 0,
            scratch_bytes_written: 0,
        })
    }

    fn push<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
        provider_set_key: i64,
        code_key: i64,
    ) -> io::Result<()> {
        self.row_count = self.row_count.saturating_add(1);
        if provider_set_key < 0 || code_key < 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 provider_set_key and code_key cannot be negative",
            ));
        }
        if code_key > i64::from(i32::MAX) {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 code_key must fit in a signed PostgreSQL integer",
            ));
        }
        let pair = (provider_set_key, code_key);
        if self.previous_pair.is_some_and(|previous| pair < previous) {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 provider/code rows must be ordered by provider_set_key, code_key",
            ));
        }
        if self.previous_pair == Some(pair) {
            self.duplicate_pair_count = self.duplicate_pair_count.saturating_add(1);
            return Ok(());
        }
        if self
            .current_provider_key
            .is_some_and(|key| key != provider_set_key)
        {
            self.finish_provider(writer, target_format)?;
        }
        self.current_provider_key = Some(provider_set_key);
        if self
            .maximum_code_keys
            .is_some_and(|maximum| self.current_code_keys.len() >= maximum)
        {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "one provider references more code keys than the finalizer dictionary",
            ));
        }
        self.current_code_keys.push(code_key);
        self.maximum_code_keys_buffered = self
            .maximum_code_keys_buffered
            .max(self.current_code_keys.len());
        self.previous_pair = Some(pair);
        self.code_count = self.code_count.saturating_add(1);
        Ok(())
    }

    fn finish_provider<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
    ) -> io::Result<()> {
        let Some(provider_set_key) = self.current_provider_key.take() else {
            return Ok(());
        };
        let block_key = serving_binary_v3_block_key(
            provider_set_key,
            PTG2_SERVING_BINARY_PROVIDER_SET_CODES_V3_BLOCK_SPAN,
            "provider_set_key",
        )?;
        if self
            .current_block_key
            .is_some_and(|current| current != block_key)
        {
            self.flush_block(writer, target_format)?;
        }
        self.current_block_key = Some(block_key);
        let code_keys = std::mem::take(&mut self.current_code_keys);
        let (code_payload, code_stats) =
            ptg2_serving_binary_v3::encode_sorted_provider_code_set(&code_keys)?;
        let block_start = i64::from(block_key)
            .checked_mul(PTG2_SERVING_BINARY_PROVIDER_SET_CODES_V3_BLOCK_SPAN)
            .ok_or_else(|| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "PTG2 v3 provider block start overflows i64",
                )
            })?;
        let relative_key = u64::try_from(provider_set_key - block_start).map_err(|_| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 provider key is outside its logical block",
            )
        })?;
        if relative_key >= PTG2_SERVING_BINARY_PROVIDER_SET_CODES_V3_BLOCK_SPAN as u64 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 provider key is outside its logical block",
            ));
        }
        let mut entry_header = Vec::with_capacity(16);
        write_uvarint_to_vec(&mut entry_header, relative_key);
        write_uvarint_to_vec(&mut entry_header, code_payload.len() as u64);
        self.block_spool.write_all(&entry_header)?;
        self.block_spool.write_all(&code_payload)?;
        let entry_bytes = u64::try_from(entry_header.len())
            .ok()
            .and_then(|header_bytes| header_bytes.checked_add(code_payload.len() as u64))
            .ok_or_else(|| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "PTG2 v3 provider-code block byte count overflows u64",
                )
            })?;
        self.block_spool_bytes =
            self.block_spool_bytes
                .checked_add(entry_bytes)
                .ok_or_else(|| {
                    io::Error::new(
                        io::ErrorKind::InvalidData,
                        "PTG2 v3 provider-code block byte count overflows u64",
                    )
                })?;
        self.scratch_bytes_written = self.scratch_bytes_written.saturating_add(entry_bytes);
        self.block_provider_count = self.block_provider_count.checked_add(1).ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 provider-code block count overflows usize",
            )
        })?;
        self.provider_set_count = self.provider_set_count.saturating_add(1);
        self.container_count = self
            .container_count
            .saturating_add(code_stats.container_count as u64);
        self.sparse_container_count = self
            .sparse_container_count
            .saturating_add(code_stats.sparse_container_count as u64);
        self.run_container_count = self
            .run_container_count
            .saturating_add(code_stats.run_container_count as u64);
        self.bitmap_container_count = self
            .bitmap_container_count
            .saturating_add(code_stats.bitmap_container_count as u64);
        Ok(())
    }

    fn flush_block<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
    ) -> io::Result<()> {
        if self.block_provider_count == 0 {
            return Ok(());
        }
        let block_key = self.current_block_key.ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 provider block is missing its block key",
            )
        })?;
        self.block_spool.flush()?;
        let mut block_prefix = Vec::with_capacity(8);
        write_uvarint_to_vec(&mut block_prefix, self.block_provider_count as u64);
        let scratch_bytes_read = write_serving_binary_v3_spooled_logical_block(
            writer,
            target_format,
            self.max_payload_bytes,
            ServingBinaryV3SpoolBlock {
                artifact_kind: PTG2_SERVING_BINARY_PROVIDER_SET_CODES_V3_KIND,
                block_key,
                entry_count: self.block_provider_count,
                prefix: &block_prefix,
                spool_bytes: self.block_spool_bytes,
            },
            &mut self.block_spool,
            &mut self.block_stats,
        )?;
        self.scratch_bytes_read = self.scratch_bytes_read.saturating_add(scratch_bytes_read);
        self.block_spool.set_len(0)?;
        self.block_spool.seek(SeekFrom::Start(0))?;
        self.block_spool_bytes = 0;
        self.block_provider_count = 0;
        Ok(())
    }

    fn finish<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
    ) -> io::Result<()> {
        self.finish_provider(writer, target_format)?;
        self.flush_block(writer, target_format)
    }
}

struct ServingBinaryV3PriceMembershipState {
    max_payload_bytes: usize,
    atom_key_bits: u8,
    previous_pair: Option<(i64, i64)>,
    current_price_key: Option<i64>,
    current_atom_keys: Vec<i64>,
    current_block_key: Option<i32>,
    memberships: Vec<(i64, Vec<i64>)>,
    block_stats: ServingBinaryV3BlockStats,
    row_count: u64,
    price_set_count: u64,
    maximum_price_key: Option<i64>,
}

impl ServingBinaryV3PriceMembershipState {
    fn new(max_payload_bytes: usize, atom_key_bits: u8) -> Self {
        Self {
            max_payload_bytes,
            atom_key_bits,
            previous_pair: None,
            current_price_key: None,
            current_atom_keys: Vec::new(),
            current_block_key: None,
            memberships: Vec::new(),
            block_stats: ServingBinaryV3BlockStats::default(),
            row_count: 0,
            price_set_count: 0,
            maximum_price_key: None,
        }
    }

    fn push<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
        price_key: i64,
        atom_key: i64,
    ) -> io::Result<()> {
        if price_key < 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 price_key cannot be negative",
            ));
        }
        serving_binary_v3_validate_atom_key(atom_key, self.atom_key_bits)?;
        let pair = (price_key, atom_key);
        if self.previous_pair.is_some_and(|previous| pair < previous) {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 price/atom rows must be ordered by price_key, atom_key",
            ));
        }
        if self.current_price_key.is_some_and(|key| key != price_key) {
            self.finish_membership(writer, target_format)?;
        }
        self.current_price_key = Some(price_key);
        self.current_atom_keys.push(atom_key);
        self.previous_pair = Some(pair);
        self.row_count = self.row_count.saturating_add(1);
        self.maximum_price_key = Some(price_key);
        Ok(())
    }

    fn finish_membership<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
    ) -> io::Result<()> {
        let Some(price_key) = self.current_price_key.take() else {
            return Ok(());
        };
        let block_key = serving_binary_v3_block_key(
            price_key,
            PTG2_SERVING_BINARY_PRICE_MEMBERSHIPS_V3_BLOCK_SPAN,
            "price_key",
        )?;
        if self
            .current_block_key
            .is_some_and(|current| current != block_key)
        {
            self.flush_block(writer, target_format)?;
        }
        self.current_block_key = Some(block_key);
        self.memberships
            .push((price_key, std::mem::take(&mut self.current_atom_keys)));
        self.price_set_count = self.price_set_count.saturating_add(1);
        Ok(())
    }

    fn flush_block<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
    ) -> io::Result<()> {
        if self.memberships.is_empty() {
            return Ok(());
        }
        let block_key = self.current_block_key.ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 price membership block is missing its block key",
            )
        })?;
        let memberships = std::mem::take(&mut self.memberships);
        let block_payload =
            ptg2_serving_binary_v3::encode_price_memberships(&memberships, self.atom_key_bits)?;
        write_serving_binary_v3_logical_block(
            writer,
            target_format,
            self.max_payload_bytes,
            ServingBinaryV3LogicalBlock {
                artifact_kind: PTG2_SERVING_BINARY_PRICE_SET_ATOM_MEMBERSHIPS_V3_KIND,
                block_key,
                entry_count: memberships.len(),
                payload: &block_payload,
            },
            &mut self.block_stats,
        )
    }

    fn finish<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
    ) -> io::Result<()> {
        self.finish_membership(writer, target_format)?;
        self.flush_block(writer, target_format)
    }
}

struct ServingBinaryV3PriceAtomState {
    max_payload_bytes: usize,
    atom_key_bits: u8,
    expected_atom_key: i64,
    current_block_key: Option<i32>,
    price_atoms: Vec<ptg2_serving_binary_v3::PriceAtomRecord>,
    block_stats: ServingBinaryV3BlockStats,
}

impl ServingBinaryV3PriceAtomState {
    fn new(max_payload_bytes: usize, atom_key_bits: u8) -> Self {
        Self {
            max_payload_bytes,
            atom_key_bits,
            expected_atom_key: 0,
            current_block_key: None,
            price_atoms: Vec::with_capacity(PTG2_SERVING_BINARY_PRICE_ATOMS_V3_BLOCK_SPAN as usize),
            block_stats: ServingBinaryV3BlockStats::default(),
        }
    }

    fn push<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
        atom_key: i64,
        negotiated_rate: Option<String>,
        attribute_keys: Vec<Option<i64>>,
    ) -> io::Result<()> {
        if atom_key != self.expected_atom_key {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                format!(
                    "PTG2 v3 atom keys must be dense and ordered from zero: expected {}, got {atom_key}",
                    self.expected_atom_key
                ),
            ));
        }
        serving_binary_v3_validate_atom_key(atom_key, self.atom_key_bits)?;
        if attribute_keys.len() != PTG2_SERVING_BINARY_PRICE_ATOM_V3_ATTRIBUTE_COUNT {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                format!(
                    "PTG2 v3 price atom rows must have {PTG2_SERVING_BINARY_PRICE_ATOM_V3_ATTRIBUTE_COUNT} attribute keys"
                ),
            ));
        }
        let block_key = serving_binary_v3_block_key(
            atom_key,
            PTG2_SERVING_BINARY_PRICE_ATOMS_V3_BLOCK_SPAN,
            "atom_key",
        )?;
        if self
            .current_block_key
            .is_some_and(|current| current != block_key)
        {
            self.flush_block(writer, target_format)?;
        }
        self.current_block_key = Some(block_key);
        self.price_atoms
            .push(ptg2_serving_binary_v3::PriceAtomRecord {
                negotiated_rate,
                attribute_keys,
            });
        self.expected_atom_key = self.expected_atom_key.checked_add(1).ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 atom key overflowed i64",
            )
        })?;
        Ok(())
    }

    fn flush_block<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
    ) -> io::Result<()> {
        if self.price_atoms.is_empty() {
            return Ok(());
        }
        let block_key = self.current_block_key.ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 price atom block is missing its block key",
            )
        })?;
        let price_atoms = std::mem::take(&mut self.price_atoms);
        let block_payload = ptg2_serving_binary_v3::encode_price_atoms(&price_atoms)?;
        write_serving_binary_v3_logical_block(
            writer,
            target_format,
            self.max_payload_bytes,
            ServingBinaryV3LogicalBlock {
                artifact_kind: PTG2_SERVING_BINARY_PRICE_ATOMS_V3_KIND,
                block_key,
                entry_count: price_atoms.len(),
                payload: &block_payload,
            },
            &mut self.block_stats,
        )
    }

    fn finish<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
    ) -> io::Result<()> {
        self.flush_block(writer, target_format)
    }
}

#[cfg(test)]
fn write_serving_binary_v3_provider_codes_copy_from_pg_binary_reader<R: Read, W: Write>(
    reader: &mut R,
    writer: &mut CountingWriter<W>,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
) -> io::Result<Value> {
    read_pg_binary_copy_header(reader)?;
    write_serving_binary_copy_header(writer, target_format)?;
    let mut state = ServingBinaryV3ProviderCodeState::new(max_payload_bytes, None)?;
    while let Some(fields) = read_pg_binary_copy_row(reader, 2, "PTG2 v3 provider codes")? {
        let provider_set_key = pg_binary_nonnegative_i64(
            required_pg_binary_field(&fields, 0, "provider_set_key")?,
            "provider_set_key",
        )?;
        let code_key = pg_binary_nonnegative_i64(
            required_pg_binary_field(&fields, 1, "code_key")?,
            "code_key",
        )?;
        state.push(writer, target_format, provider_set_key, code_key)?;
    }
    state.finish(writer, target_format)?;
    write_serving_binary_copy_trailer(writer, target_format)?;
    writer.hydrate_shared_block_stats(
        PTG2_SERVING_BINARY_PROVIDER_SET_CODES_V3_KIND,
        &mut state.block_stats,
    )?;
    writer.flush()?;
    Ok(json!({
        "name": "serving_binary_v3_provider_set_codes",
        "format": PTG2_SERVING_BINARY_V3_FORMAT,
        "encoder_kind": PTG2_SERVING_BINARY_PROVIDER_SET_CODES_V3_KIND,
        "artifact_kind": PTG2_SERVING_BINARY_PROVIDER_SET_CODES_V3_KIND,
        "row_count": state.row_count,
        "pair_count": state.code_count,
        "duplicate_pair_count": state.duplicate_pair_count,
        "provider_set_count": state.provider_set_count,
        "code_count": state.code_count,
        "container_count": state.container_count,
        "sparse_container_count": state.sparse_container_count,
        "run_container_count": state.run_container_count,
        "bitmap_container_count": state.bitmap_container_count,
        "block_span": PTG2_SERVING_BINARY_PROVIDER_SET_CODES_V3_BLOCK_SPAN,
        "block_count": state.block_stats.logical_block_count,
        "copy_record_count": state.block_stats.copy_record_count,
        "block_bytes": max_payload_bytes,
        "byte_count": writer.byte_count(),
        "source_copy_format": "postgres_binary",
        "target_copy_format": target_format.label(),
        "storage": state.block_stats.storage_summary(),
    }))
}

fn write_serving_binary_v3_memberships_copy_from_pg_binary_reader<R: Read, W: Write>(
    reader: &mut R,
    writer: &mut CountingWriter<W>,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    atom_key_bits: u8,
) -> io::Result<Value> {
    read_pg_binary_copy_header(reader)?;
    write_serving_binary_copy_header(writer, target_format)?;
    let mut state = ServingBinaryV3PriceMembershipState::new(max_payload_bytes, atom_key_bits);
    while let Some(fields) = read_pg_binary_copy_row(reader, 2, "PTG2 v3 price memberships")? {
        let price_key = pg_binary_nonnegative_i64(
            required_pg_binary_field(&fields, 0, "price_key")?,
            "price_key",
        )?;
        let atom_key = pg_binary_nonnegative_i64(
            required_pg_binary_field(&fields, 1, "atom_key")?,
            "atom_key",
        )?;
        state.push(writer, target_format, price_key, atom_key)?;
    }
    state.finish(writer, target_format)?;
    write_serving_binary_copy_trailer(writer, target_format)?;
    writer.hydrate_shared_block_stats(
        PTG2_SERVING_BINARY_PRICE_SET_ATOM_MEMBERSHIPS_V3_KIND,
        &mut state.block_stats,
    )?;
    writer.flush()?;
    Ok(json!({
        "name": "serving_binary_v3_price_set_atom_memberships",
        "format": PTG2_SERVING_BINARY_V3_FORMAT,
        "encoder_kind": PTG2_SERVING_BINARY_PRICE_SET_ATOM_MEMBERSHIPS_V3_KIND,
        "artifact_kind": PTG2_SERVING_BINARY_PRICE_SET_ATOM_MEMBERSHIPS_V3_KIND,
        "row_count": state.row_count,
        "price_set_count": state.price_set_count,
        "atom_reference_count": state.row_count,
        "maximum_price_key": state.maximum_price_key,
        "atom_key_bits": atom_key_bits,
        "atom_key_bytes": atom_key_bits / 8,
        "block_span": PTG2_SERVING_BINARY_PRICE_MEMBERSHIPS_V3_BLOCK_SPAN,
        "block_count": state.block_stats.logical_block_count,
        "copy_record_count": state.block_stats.copy_record_count,
        "block_bytes": max_payload_bytes,
        "byte_count": writer.byte_count(),
        "source_copy_format": "postgres_binary",
        "target_copy_format": target_format.label(),
        "storage": state.block_stats.storage_summary(),
    }))
}

fn write_serving_binary_v3_price_atoms_copy_from_pg_binary_reader<R: Read, W: Write>(
    reader: &mut R,
    writer: &mut CountingWriter<W>,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    atom_key_bits: u8,
) -> io::Result<Value> {
    read_pg_binary_copy_header(reader)?;
    write_serving_binary_copy_header(writer, target_format)?;
    let mut state = ServingBinaryV3PriceAtomState::new(max_payload_bytes, atom_key_bits);
    while let Some(fields) = read_pg_binary_copy_row(reader, 9, "PTG2 v3 price atoms")? {
        let atom_key = pg_binary_nonnegative_i64(
            required_pg_binary_field(&fields, 0, "atom_key")?,
            "atom_key",
        )?;
        let negotiated_rate = fields[1]
            .as_deref()
            .map(pg_binary_negotiated_rate)
            .transpose()?;
        let mut attribute_keys =
            Vec::with_capacity(PTG2_SERVING_BINARY_PRICE_ATOM_V3_ATTRIBUTE_COUNT);
        for attribute_index in 0..PTG2_SERVING_BINARY_PRICE_ATOM_V3_ATTRIBUTE_COUNT {
            attribute_keys.push(pg_binary_optional_nonnegative_i64(
                fields[attribute_index + 2].as_deref(),
                &format!("attribute_key_{}", attribute_index + 1),
            )?);
        }
        state.push(
            writer,
            target_format,
            atom_key,
            negotiated_rate,
            attribute_keys,
        )?;
    }
    state.finish(writer, target_format)?;
    write_serving_binary_copy_trailer(writer, target_format)?;
    writer.hydrate_shared_block_stats(
        PTG2_SERVING_BINARY_PRICE_ATOMS_V3_KIND,
        &mut state.block_stats,
    )?;
    writer.flush()?;
    Ok(json!({
        "name": "serving_binary_v3_price_atoms",
        "format": PTG2_SERVING_BINARY_V3_FORMAT,
        "encoder_kind": PTG2_SERVING_BINARY_PRICE_ATOMS_V3_KIND,
        "artifact_kind": PTG2_SERVING_BINARY_PRICE_ATOMS_V3_KIND,
        "atom_count": state.expected_atom_key,
        "attribute_count": PTG2_SERVING_BINARY_PRICE_ATOM_V3_ATTRIBUTE_COUNT,
        "atom_key_bits": atom_key_bits,
        "atom_key_bytes": atom_key_bits / 8,
        "block_span": PTG2_SERVING_BINARY_PRICE_ATOMS_V3_BLOCK_SPAN,
        "block_count": state.block_stats.logical_block_count,
        "copy_record_count": state.block_stats.copy_record_count,
        "block_bytes": max_payload_bytes,
        "byte_count": writer.byte_count(),
        "source_copy_format": "postgres_binary",
        "target_copy_format": target_format.label(),
        "storage": state.block_stats.storage_summary(),
    }))
}

fn strict_v3_price_copy_stdio_usage() -> &'static str {
    "usage: ptg2_scanner --serving-binary-copy-from-key-copy-stdio \
<price_set_atom_memberships_v3|price_atoms_v3> <24|32>"
}

fn write_strict_v3_price_copy_from_pg_binary_stdio(
    kind: &str,
    options: &[String],
) -> io::Result<()> {
    if options.len() != 1 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            strict_v3_price_copy_stdio_usage(),
        ));
    }
    let atom_key_bits = serving_binary_v3_atom_key_bits(&options[0])?;
    let stdin = io::stdin();
    let stdout = io::stdout();
    let mut reader = BufReader::new(stdin.lock());
    let mut writer = CountingWriter::new(BufWriter::new(stdout.lock()));
    let target_format = ServingBinaryTargetCopyFormat::SharedBinary;
    let summary = match kind {
        PTG2_SERVING_BINARY_PRICE_SET_ATOM_MEMBERSHIPS_V3_KIND => {
            write_serving_binary_v3_memberships_copy_from_pg_binary_reader(
                &mut reader,
                &mut writer,
                target_format,
                serving_binary_block_bytes(),
                atom_key_bits,
            )?
        }
        PTG2_SERVING_BINARY_PRICE_ATOMS_V3_KIND => {
            write_serving_binary_v3_price_atoms_copy_from_pg_binary_reader(
                &mut reader,
                &mut writer,
                target_format,
                serving_binary_block_bytes(),
                atom_key_bits,
            )?
        }
        _ => {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                strict_v3_price_copy_stdio_usage(),
            ));
        }
    };
    writeln!(io::stderr().lock(), "PTG2_SERVING_BINARY_COPY\t{summary}")
}

#[derive(Clone, Copy)]
struct SourceEncoding {
    count: u64,
    key_bits: u8,
    tagged_codec: TaggedServingRunCodec,
}

#[derive(Clone, Copy)]
struct AssignedV3EncoderOptions {
    grouped_payload_bytes: usize,
    hot_payload_bytes: usize,
    provider_code_sort_chunk_bytes: usize,
    provider_set_count: Option<usize>,
    provider_code_count: Option<usize>,
    provider_code_bitmap_max_bytes: usize,
    source: SourceEncoding,
}

fn validate_source_encoding(source_count: u64, source_bits: u8) -> io::Result<()> {
    let expected_bits = source_key_bits(source_count)?;
    if source_bits != expected_bits {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            format!(
                "source_key_bits mismatch for source_count {source_count}: expected {expected_bits}, got {source_bits}"
            ),
        ));
    }
    Ok(())
}

fn append_source_encoding_header(
    payload: &mut Vec<u8>,
    format_version: u8,
    source_count: u64,
    source_bits: u8,
) -> io::Result<()> {
    validate_source_encoding(source_count, source_bits)?;
    payload.push(format_version);
    write_uvarint_to_vec(payload, source_count);
    payload.push(source_bits);
    Ok(())
}

fn encode_source_key_vector(
    source_keys: &[u32],
    source_count: u64,
    source_bits: u8,
) -> io::Result<Vec<u8>> {
    validate_source_encoding(source_count, source_bits)?;
    let total_bits = source_keys
        .len()
        .checked_mul(usize::from(source_bits))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "source provenance bit count overflows usize",
            )
        })?;
    let mut encoded = vec![0u8; total_bits.div_ceil(8)];
    let mut bit_offset = 0usize;
    for &source_key in source_keys {
        if u64::from(source_key) >= source_count {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                format!("source_key {source_key} is outside dense source_count {source_count}"),
            ));
        }
        for source_bit in 0..source_bits {
            if source_key & (1u32 << source_bit) != 0 {
                encoded[bit_offset / 8] |= 1u8 << (bit_offset % 8);
            }
            bit_offset += 1;
        }
    }
    Ok(encoded)
}

fn serving_binary_by_code_provider_shard_no(provider_set_key: i32) -> io::Result<i64> {
    if provider_set_key < 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "provider_set_key cannot be negative",
        ));
    }
    Ok(i64::from(provider_set_key) / PTG2_SERVING_BINARY_BY_CODE_PROVIDER_SHARD_SPAN)
}

fn serving_binary_by_code_provider_shard_block_key(
    code_key: i32,
    provider_set_key: i32,
) -> io::Result<i64> {
    if code_key < 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "code_key cannot be negative",
        ));
    }
    let shard_no = serving_binary_by_code_provider_shard_no(provider_set_key)?;
    if shard_no >= (1i64 << 31) {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "provider shard number exceeds its 31-bit block-key field",
        ));
    }
    Ok((i64::from(code_key) << 31) | shard_no)
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct ServingByCodeGroupLayout {
    provider_delta: u64,
    encoded_bytes: usize,
}

fn serving_by_code_group_layout(
    provider_set_key: i32,
    previous_provider_set_key: i32,
    occurrence_count: usize,
    price_payload: &[u8],
    source_payload: &[u8],
) -> io::Result<ServingByCodeGroupLayout> {
    if provider_set_key < previous_provider_set_key {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "serving-binary grouped by-code rows must be ordered by provider_set_key within code_key",
        ));
    }
    if occurrence_count == 0 {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "grouped by-code occurrence chunk cannot be empty",
        ));
    }
    let provider_delta = (provider_set_key - previous_provider_set_key) as u64;
    let encoded_bytes = uvarint_encoded_len(provider_delta)
        .checked_add(uvarint_encoded_len(occurrence_count as u64))
        .and_then(|value| value.checked_add(price_payload.len()))
        .and_then(|value| value.checked_add(source_payload.len()))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code payload size overflows usize",
            )
        })?;
    Ok(ServingByCodeGroupLayout {
        provider_delta,
        encoded_bytes,
    })
}

fn append_serving_by_code_group(
    output: &mut Vec<u8>,
    layout: ServingByCodeGroupLayout,
    occurrence_count: usize,
    price_payload: &[u8],
    source_payload: &[u8],
) {
    let initial_bytes = output.len();
    write_uvarint_to_vec(output, layout.provider_delta);
    write_uvarint_to_vec(output, occurrence_count as u64);
    output.extend_from_slice(price_payload);
    output.extend_from_slice(source_payload);
    debug_assert_eq!(output.len() - initial_bytes, layout.encoded_bytes);
}

fn serving_by_code_group_standalone_bytes(
    provider_set_key: i32,
    occurrence_count: usize,
    price_uvarint_bytes: usize,
    source_count: u64,
    source_bits: u8,
) -> io::Result<usize> {
    validate_source_encoding(source_count, source_bits)?;
    let provider_key = u64::try_from(provider_set_key).map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "provider_set_key cannot be negative",
        )
    })?;
    let source_bytes = occurrence_count
        .checked_mul(usize::from(source_bits))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code source bit count overflows usize",
            )
        })?
        .div_ceil(8);
    2usize
        .checked_add(uvarint_encoded_len(source_count))
        .and_then(|value| value.checked_add(uvarint_encoded_len(provider_key)))
        .and_then(|value| value.checked_add(uvarint_encoded_len(occurrence_count as u64)))
        .and_then(|value| value.checked_add(price_uvarint_bytes))
        .and_then(|value| value.checked_add(source_bytes))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code payload size overflows usize",
            )
        })
}

struct ServingBinaryByCodeProviderShardState {
    current_code: Option<i32>,
    current_block_key: Option<i64>,
    max_payload_bytes: usize,
    fragment_no: usize,
    current_entry_count: usize,
    previous_provider_set_key: i32,
    current_payload: Vec<u8>,
    current_provider_set_key: Option<i32>,
    current_occurrence_count: usize,
    current_price_payload: Vec<u8>,
    current_source_payload: Vec<u8>,
    current_group_is_continuation: bool,
    source_count: u64,
    source_bits: u8,
    copy_record_count: u64,
    logical_block_count: u64,
    group_count: u64,
    occurrence_chunk_count: u64,
    maximum_occurrences_buffered: usize,
    direct_group_payload_bytes: u64,
}

impl ServingBinaryByCodeProviderShardState {
    fn new(max_payload_bytes: usize, source_count: u64, source_bits: u8) -> io::Result<Self> {
        if max_payload_bytes == 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                "by-code provider shard payload limit must be positive",
            ));
        }
        validate_source_encoding(source_count, source_bits)?;
        Ok(Self {
            current_code: None,
            current_block_key: None,
            max_payload_bytes,
            fragment_no: 0,
            current_entry_count: 0,
            previous_provider_set_key: 0,
            current_payload: Vec::with_capacity(max_payload_bytes.min(1024 * 1024)),
            current_provider_set_key: None,
            current_occurrence_count: 0,
            current_price_payload: Vec::new(),
            current_source_payload: Vec::new(),
            current_group_is_continuation: false,
            source_count,
            source_bits,
            copy_record_count: 0,
            logical_block_count: 0,
            group_count: 0,
            occurrence_chunk_count: 0,
            maximum_occurrences_buffered: 0,
            direct_group_payload_bytes: 0,
        })
    }

    fn begin_logical_shard(&mut self, code_key: i32, block_key: i64) -> io::Result<()> {
        if self.current_entry_count != 0 || !self.current_payload.is_empty() {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "cannot begin a by-code provider shard before flushing the previous shard",
            ));
        }
        self.current_code = Some(code_key);
        self.current_block_key = Some(block_key);
        self.fragment_no = 0;
        self.previous_provider_set_key = 0;
        self.current_provider_set_key = None;
        self.current_group_is_continuation = false;
        self.logical_block_count = self.logical_block_count.saturating_add(1);
        Ok(())
    }
}

fn flush_serving_binary_by_code_provider_shard_fragment<W: SharedBlockCopyWriter>(
    writer: &mut W,
    state: &mut ServingBinaryByCodeProviderShardState,
    target_format: ServingBinaryTargetCopyFormat,
) -> io::Result<()> {
    if state.current_entry_count == 0 {
        return Ok(());
    }
    let block_key = state.current_block_key.ok_or_else(|| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "by-code provider shard payload has no logical block key",
        )
    })?;
    write_serving_binary_copy_record_with_i64_key_and_stats(
        writer,
        target_format,
        PTG2_SERVING_BINARY_BY_CODE_PROVIDER_SHARD_KIND,
        block_key,
        state.fragment_no,
        state.current_entry_count,
        &state.current_payload,
    )?;
    state.copy_record_count = state.copy_record_count.saturating_add(1);
    state.current_payload.clear();
    state.current_entry_count = 0;
    Ok(())
}

fn append_serving_binary_by_code_provider_group<W: SharedBlockCopyWriter>(
    writer: &mut W,
    state: &mut ServingBinaryByCodeProviderShardState,
    target_format: ServingBinaryTargetCopyFormat,
) -> io::Result<()> {
    let Some(provider_set_key) = state.current_provider_set_key else {
        state.current_occurrence_count = 0;
        state.current_price_payload.clear();
        state.current_source_payload.clear();
        return Ok(());
    };
    if state.current_occurrence_count == 0 {
        return Ok(());
    }
    let Some(_code_key) = state.current_code else {
        state.current_occurrence_count = 0;
        state.current_price_payload.clear();
        state.current_source_payload.clear();
        return Ok(());
    };
    if state.current_payload.is_empty() {
        append_source_encoding_header(
            &mut state.current_payload,
            PTG2_SERVING_BINARY_V3_GROUPED_FORMAT_VERSION,
            state.source_count,
            state.source_bits,
        )?;
    }
    let mut layout = serving_by_code_group_layout(
        provider_set_key,
        state.previous_provider_set_key,
        state.current_occurrence_count,
        &state.current_price_payload,
        &state.current_source_payload,
    )?;
    if state.current_entry_count > 0
        && state
            .current_payload
            .len()
            .checked_add(layout.encoded_bytes)
            .is_none_or(|payload_bytes| payload_bytes > state.max_payload_bytes)
    {
        flush_serving_binary_by_code_provider_shard_fragment(writer, state, target_format)?;
        state.fragment_no = state.fragment_no.checked_add(1).ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "by-code provider shard fragment number overflows usize",
            )
        })?;
        state.previous_provider_set_key = 0;
        append_source_encoding_header(
            &mut state.current_payload,
            PTG2_SERVING_BINARY_V3_GROUPED_FORMAT_VERSION,
            state.source_count,
            state.source_bits,
        )?;
        layout = serving_by_code_group_layout(
            provider_set_key,
            0,
            state.current_occurrence_count,
            &state.current_price_payload,
            &state.current_source_payload,
        )?;
    }
    if state
        .current_payload
        .len()
        .checked_add(layout.encoded_bytes)
        .is_none_or(|payload_bytes| payload_bytes > state.max_payload_bytes)
    {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "one grouped by-code occurrence chunk exceeds its payload limit",
        ));
    }
    append_serving_by_code_group(
        &mut state.current_payload,
        layout,
        state.current_occurrence_count,
        &state.current_price_payload,
        &state.current_source_payload,
    );
    state.direct_group_payload_bytes = state
        .direct_group_payload_bytes
        .saturating_add(layout.encoded_bytes as u64);
    state.current_entry_count += 1;
    state.previous_provider_set_key = provider_set_key;
    if !state.current_group_is_continuation {
        state.group_count = state.group_count.saturating_add(1);
    }
    state.occurrence_chunk_count = state.occurrence_chunk_count.saturating_add(1);
    state.current_occurrence_count = 0;
    state.current_price_payload.clear();
    state.current_source_payload.clear();
    Ok(())
}

fn push_serving_binary_by_code_occurrence<W: SharedBlockCopyWriter>(
    writer: &mut W,
    state: &mut ServingBinaryByCodeProviderShardState,
    target_format: ServingBinaryTargetCopyFormat,
    price_key: u32,
    source_key: u32,
) -> io::Result<()> {
    let provider_set_key = state.current_provider_set_key.ok_or_else(|| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "grouped by-code occurrence has no provider_set_key",
        )
    })?;
    if u64::from(source_key) >= state.source_count {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "source_key {source_key} is outside dense source_count {}",
                state.source_count
            ),
        ));
    }
    let next_count = state
        .current_occurrence_count
        .checked_add(1)
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code occurrence count overflows usize",
            )
        })?;
    let next_price_bytes = state
        .current_price_payload
        .len()
        .checked_add(uvarint_encoded_len(u64::from(price_key)))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code price byte count overflows usize",
            )
        })?;
    let next_standalone_bytes = serving_by_code_group_standalone_bytes(
        provider_set_key,
        next_count,
        next_price_bytes,
        state.source_count,
        state.source_bits,
    )?;
    let mut appended_count = next_count;
    if next_standalone_bytes > state.max_payload_bytes {
        if state.current_occurrence_count == 0 {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "one grouped by-code occurrence cannot fit in the configured payload limit",
            ));
        }
        append_serving_binary_by_code_provider_group(writer, state, target_format)?;
        state.current_group_is_continuation = true;
        appended_count = 1;
        let single_occurrence_bytes = serving_by_code_group_standalone_bytes(
            provider_set_key,
            1,
            uvarint_encoded_len(u64::from(price_key)),
            state.source_count,
            state.source_bits,
        )?;
        if single_occurrence_bytes > state.max_payload_bytes {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "one grouped by-code occurrence cannot fit in the configured payload limit",
            ));
        }
    }
    write_uvarint_to_vec(&mut state.current_price_payload, u64::from(price_key));
    let source_bit_offset = state
        .current_occurrence_count
        .checked_mul(usize::from(state.source_bits))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code source bit offset overflows usize",
            )
        })?;
    let next_source_bits = appended_count
        .checked_mul(usize::from(state.source_bits))
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "grouped by-code source bit count overflows usize",
            )
        })?;
    state
        .current_source_payload
        .resize(next_source_bits.div_ceil(8), 0);
    for source_bit in 0..state.source_bits {
        if source_key & (1u32 << source_bit) != 0 {
            let bit_offset = source_bit_offset + usize::from(source_bit);
            state.current_source_payload[bit_offset / 8] |= 1u8 << (bit_offset % 8);
        }
    }
    state.current_occurrence_count = appended_count;
    state.maximum_occurrences_buffered = state
        .maximum_occurrences_buffered
        .max(state.current_occurrence_count);
    Ok(())
}

type ServingBinaryV3ForwardPageCandidate = (u32, i32, u32, u64);

fn push_serving_binary_v3_forward_page_candidate(
    candidates: &mut BinaryHeap<ServingBinaryV3ForwardPageCandidate>,
    candidate: ServingBinaryV3ForwardPageCandidate,
) {
    if candidates.len() < PTG2_SERVING_BINARY_V3_PAGE_ROWS {
        candidates.push(candidate);
        return;
    }
    if candidates
        .peek()
        .is_some_and(|worst_candidate| candidate < *worst_candidate)
    {
        candidates.pop();
        candidates.push(candidate);
    }
}

fn write_serving_binary_v3_forward_page<W: SharedBlockCopyWriter>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    code_key: Option<i32>,
    candidates: &mut BinaryHeap<ServingBinaryV3ForwardPageCandidate>,
    block_stats: &mut ServingBinaryV3BlockStats,
    source: SourceEncoding,
) -> io::Result<()> {
    let Some(code_key) = code_key else {
        candidates.clear();
        return Ok(());
    };
    if candidates.is_empty() {
        return Ok(());
    }
    let mut ordered_candidates = candidates.drain().collect::<Vec<_>>();
    ordered_candidates.sort_unstable();
    let mut payload = Vec::with_capacity(4 + ordered_candidates.len() * 8);
    append_source_encoding_header(
        &mut payload,
        PTG2_SERVING_BINARY_PAGE_FORMAT_VERSION,
        source.count,
        source.key_bits,
    )?;
    write_uvarint_to_vec(&mut payload, ordered_candidates.len() as u64);
    for (price_key, provider_set_key, _, provider_count) in &ordered_candidates {
        write_uvarint_to_vec(&mut payload, *provider_set_key as u64);
        write_uvarint_to_vec(&mut payload, *provider_count);
        write_uvarint_to_vec(&mut payload, u64::from(*price_key));
    }
    payload.extend_from_slice(&encode_source_key_vector(
        &ordered_candidates
            .iter()
            .map(|(_, _, source_key, _)| *source_key)
            .collect::<Vec<_>>(),
        source.count,
        source.key_bits,
    )?);
    write_serving_binary_v3_logical_block(
        writer,
        target_format,
        max_payload_bytes,
        ServingBinaryV3LogicalBlock {
            artifact_kind: PTG2_SERVING_BINARY_BY_CODE_PRICE_PAGE_V4_KIND,
            block_key: code_key,
            entry_count: ordered_candidates.len(),
            payload: &payload,
        },
        block_stats,
    )
}

struct ServingBinaryV3ProviderProjection {
    provider_count: u64,
    total_row_count: u64,
    page_rows: Vec<(i32, u32, u32)>,
}

enum ServingBinaryV3ProviderProjections {
    Dense {
        entries: Vec<Option<ServingBinaryV3ProviderProjection>>,
        populated_entries: usize,
    },
    Sparse {
        entries: BTreeMap<i32, ServingBinaryV3ProviderProjection>,
        storage_kind: &'static str,
        expected_entries: Option<usize>,
    },
}

enum ServingBinaryV3ProviderProjectionIter<'a> {
    Dense {
        entries: &'a [Option<ServingBinaryV3ProviderProjection>],
        next_index: usize,
    },
    Sparse(std::collections::btree_map::Iter<'a, i32, ServingBinaryV3ProviderProjection>),
}

impl<'a> Iterator for ServingBinaryV3ProviderProjectionIter<'a> {
    type Item = (i32, &'a ServingBinaryV3ProviderProjection);

    fn next(&mut self) -> Option<Self::Item> {
        match self {
            Self::Dense {
                entries,
                next_index,
            } => {
                while *next_index < entries.len() {
                    let index = *next_index;
                    *next_index += 1;
                    if let Some(projection) = entries[index].as_ref() {
                        return Some((index as i32, projection));
                    }
                }
                None
            }
            Self::Sparse(entries) => entries.next().map(|(key, value)| (*key, value)),
        }
    }
}

impl ServingBinaryV3ProviderProjections {
    fn new(expected_provider_set_count: Option<usize>) -> Self {
        let Some(expected_provider_set_count) = expected_provider_set_count else {
            return Self::Sparse {
                entries: BTreeMap::new(),
                storage_kind: "sparse_unbounded_v1",
                expected_entries: None,
            };
        };
        if expected_provider_set_count > i32::MAX as usize + 1 {
            return Self::Sparse {
                entries: BTreeMap::new(),
                storage_kind: "sparse_key_range_fallback_v1",
                expected_entries: Some(expected_provider_set_count),
            };
        }
        let mut entries = Vec::new();
        if entries
            .try_reserve_exact(expected_provider_set_count)
            .is_err()
        {
            return Self::Sparse {
                entries: BTreeMap::new(),
                storage_kind: "sparse_allocation_fallback_v1",
                expected_entries: Some(expected_provider_set_count),
            };
        }
        entries.resize_with(expected_provider_set_count, || None);
        Self::Dense {
            entries,
            populated_entries: 0,
        }
    }

    fn push(
        &mut self,
        provider_set_key: i32,
        provider_count: u64,
        code_key: i32,
        price_key: u32,
        source_key: u32,
    ) -> io::Result<()> {
        let projection = match self {
            Self::Dense {
                entries,
                populated_entries,
            } => {
                let provider_index = usize::try_from(provider_set_key).map_err(|_| {
                    io::Error::new(
                        io::ErrorKind::InvalidData,
                        "provider_set_key cannot be negative",
                    )
                })?;
                let dense_entry_count = entries.len();
                let slot = entries.get_mut(provider_index).ok_or_else(|| {
                    io::Error::new(
                        io::ErrorKind::InvalidData,
                        format!(
                            "provider_set_key {provider_set_key} is outside the charged dense provider projection table of {} entries",
                            dense_entry_count,
                        ),
                    )
                })?;
                if slot.is_none() {
                    *slot = Some(ServingBinaryV3ProviderProjection {
                        provider_count,
                        total_row_count: 0,
                        page_rows: Vec::with_capacity(1),
                    });
                    *populated_entries = populated_entries.saturating_add(1);
                }
                slot.as_mut()
                    .expect("dense provider projection was inserted")
            }
            Self::Sparse {
                entries,
                expected_entries,
                ..
            } => {
                let provider_index = usize::try_from(provider_set_key).map_err(|_| {
                    io::Error::new(
                        io::ErrorKind::InvalidData,
                        "provider_set_key cannot be negative",
                    )
                })?;
                if expected_entries.is_some_and(|expected| provider_index >= expected) {
                    return Err(io::Error::new(
                        io::ErrorKind::InvalidData,
                        format!(
                            "provider_set_key {provider_set_key} is outside the charged sparse provider projection table of {} entries",
                            expected_entries.unwrap_or_default(),
                        ),
                    ));
                }
                entries.entry(provider_set_key).or_insert_with(|| {
                    ServingBinaryV3ProviderProjection {
                        provider_count,
                        total_row_count: 0,
                        page_rows: Vec::with_capacity(1),
                    }
                })
            }
        };
        update_serving_binary_v3_provider_projection(
            projection,
            provider_set_key,
            provider_count,
            code_key,
            price_key,
            source_key,
        )
    }

    fn len(&self) -> usize {
        match self {
            Self::Dense {
                populated_entries, ..
            } => *populated_entries,
            Self::Sparse { entries, .. } => entries.len(),
        }
    }

    fn iter(&self) -> ServingBinaryV3ProviderProjectionIter<'_> {
        match self {
            Self::Dense { entries, .. } => ServingBinaryV3ProviderProjectionIter::Dense {
                entries,
                next_index: 0,
            },
            Self::Sparse { entries, .. } => {
                ServingBinaryV3ProviderProjectionIter::Sparse(entries.iter())
            }
        }
    }

    fn validate_complete(&self) -> io::Result<()> {
        let (actual_entries, expected_entries) = match self {
            Self::Dense {
                entries,
                populated_entries,
            } => (*populated_entries, Some(entries.len())),
            Self::Sparse {
                entries,
                expected_entries,
                ..
            } => (entries.len(), *expected_entries),
        };
        if expected_entries.is_some_and(|expected| actual_entries != expected) {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                format!(
                    "assigned rows populated {actual_entries} provider projections, expected {} from the charged provider identity dictionary",
                    expected_entries.unwrap_or_default(),
                ),
            ));
        }
        Ok(())
    }

    fn storage_summary(&self) -> Value {
        match self {
            Self::Dense {
                entries,
                populated_entries,
            } => json!({
                "storage_kind": "dense_vec_v1",
                "entry_count": populated_entries,
                "slot_count": entries.len(),
                "dense_index_bytes": entries.len().saturating_mul(std::mem::size_of::<Option<ServingBinaryV3ProviderProjection>>()),
                "charged_max_bytes": entries.len().saturating_mul(V3_FINALIZER_PROVIDER_PROJECTION_MAX_BYTES_PER_ENTRY),
            }),
            Self::Sparse {
                entries,
                storage_kind,
                expected_entries,
            } => json!({
                "storage_kind": storage_kind,
                "entry_count": entries.len(),
                "slot_count": expected_entries,
                "dense_index_bytes": 0,
                "charged_max_bytes": expected_entries.unwrap_or(entries.len()).saturating_mul(V3_FINALIZER_PROVIDER_PROJECTION_MAX_BYTES_PER_ENTRY),
            }),
        }
    }
}

fn update_serving_binary_v3_provider_projection(
    projection: &mut ServingBinaryV3ProviderProjection,
    provider_set_key: i32,
    provider_count: u64,
    code_key: i32,
    price_key: u32,
    source_key: u32,
) -> io::Result<()> {
    if projection.provider_count != provider_count {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "provider_count changed for provider_set_key {provider_set_key}: {} != {provider_count}",
                projection.provider_count
            ),
        ));
    }
    projection.total_row_count = projection.total_row_count.saturating_add(1);
    if projection.page_rows.len() < PTG2_SERVING_BINARY_V3_PAGE_ROWS {
        projection.page_rows.push((code_key, price_key, source_key));
    }
    Ok(())
}

fn serving_binary_provider_projection_count_payload(
    projections: &ServingBinaryV3ProviderProjections,
) -> Vec<u8> {
    let mut payload = Vec::with_capacity(projections.len() * 2);
    let mut previous_provider_set_key = 0i32;
    for (provider_set_key, projection) in projections.iter() {
        write_uvarint_to_vec(
            &mut payload,
            (provider_set_key - previous_provider_set_key) as u64,
        );
        write_uvarint_to_vec(&mut payload, projection.provider_count);
        previous_provider_set_key = provider_set_key;
    }
    payload
}

fn serving_binary_v3_provider_page_block_payload(
    block_key: i32,
    provider_entries: &[(i32, &ServingBinaryV3ProviderProjection)],
    source_count: u64,
    source_bits: u8,
) -> io::Result<Vec<u8>> {
    let block_start = i64::from(block_key) * PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_BLOCK_SPAN;
    let mut payload = Vec::new();
    append_source_encoding_header(
        &mut payload,
        PTG2_SERVING_BINARY_PAGE_FORMAT_VERSION,
        source_count,
        source_bits,
    )?;
    write_uvarint_to_vec(&mut payload, provider_entries.len() as u64);
    for (provider_set_key, projection) in provider_entries {
        let relative_key = i64::from(*provider_set_key) - block_start;
        if !(0..PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_BLOCK_SPAN).contains(&relative_key) {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 provider page key is outside its logical block",
            ));
        }
        write_uvarint_to_vec(&mut payload, relative_key as u64);
        write_uvarint_to_vec(&mut payload, projection.provider_count);
        write_uvarint_to_vec(&mut payload, projection.total_row_count);
        write_uvarint_to_vec(&mut payload, projection.page_rows.len() as u64);
        let mut previous_code_key = 0i32;
        let mut previous_pair = None;
        for (code_key, price_key, source_key) in &projection.page_rows {
            let pair = (*code_key, *price_key, *source_key);
            if previous_pair.is_some_and(|previous| pair < previous) {
                return Err(io::Error::new(
                    io::ErrorKind::InvalidData,
                    "PTG2 v3 provider page rows are not ordered",
                ));
            }
            write_uvarint_to_vec(&mut payload, (*code_key - previous_code_key) as u64);
            write_uvarint_to_vec(&mut payload, u64::from(*price_key));
            previous_code_key = *code_key;
            previous_pair = Some(pair);
        }
        payload.extend_from_slice(&encode_source_key_vector(
            &projection
                .page_rows
                .iter()
                .map(|(_, _, source_key)| *source_key)
                .collect::<Vec<_>>(),
            source_count,
            source_bits,
        )?);
    }
    Ok(payload)
}

fn write_serving_binary_v3_provider_pages<W: SharedBlockCopyWriter>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    max_payload_bytes: usize,
    projections: &ServingBinaryV3ProviderProjections,
    block_stats: &mut ServingBinaryV3BlockStats,
    source_count: u64,
    source_bits: u8,
) -> io::Result<()> {
    let mut current_block_key = None;
    let mut provider_entries = Vec::new();
    for (provider_set_key, projection) in projections.iter() {
        let block_key = serving_binary_v3_block_key(
            i64::from(provider_set_key),
            PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_BLOCK_SPAN,
            "provider_set_key",
        )?;
        if current_block_key.is_some_and(|current| current != block_key) {
            let payload = serving_binary_v3_provider_page_block_payload(
                current_block_key.unwrap_or_default(),
                &provider_entries,
                source_count,
                source_bits,
            )?;
            write_serving_binary_v3_logical_block(
                writer,
                target_format,
                max_payload_bytes,
                ServingBinaryV3LogicalBlock {
                    artifact_kind: PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_KIND,
                    block_key: current_block_key.unwrap_or_default(),
                    entry_count: provider_entries.len(),
                    payload: &payload,
                },
                block_stats,
            )?;
            provider_entries.clear();
        }
        current_block_key = Some(block_key);
        provider_entries.push((provider_set_key, projection));
    }
    if let Some(block_key) = current_block_key {
        let payload = serving_binary_v3_provider_page_block_payload(
            block_key,
            &provider_entries,
            source_count,
            source_bits,
        )?;
        write_serving_binary_v3_logical_block(
            writer,
            target_format,
            max_payload_bytes,
            ServingBinaryV3LogicalBlock {
                artifact_kind: PTG2_SERVING_BINARY_PROVIDER_SET_PAGE_V3_KIND,
                block_key,
                entry_count: provider_entries.len(),
                payload: &payload,
            },
            block_stats,
        )?;
    }
    Ok(())
}

const SERVING_BINARY_V3_PROVIDER_CODE_MERGE_FAN_IN: usize = 64;

struct ServingBinaryV3ProviderCodeSpool {
    path: PathBuf,
    writer: BufWriter<File>,
    row_count: u64,
}

#[derive(Default)]
struct ServingBinaryV3ProviderCodeSortSummary {
    input_pair_count: u64,
    unique_pair_count: u64,
    spill_bytes: u64,
    scratch_read_bytes: u64,
    scratch_written_bytes: u64,
    chunk_count: u64,
    merge_pass_count: usize,
    maximum_merge_fan_in: usize,
    external_sort: bool,
    index_mode: &'static str,
    bitmap_candidate_bytes: Option<u64>,
    bitmap_charged_bytes: u64,
    bitmap_maximum_bytes: u64,
    bitmap_fallback_reason: Option<&'static str>,
}

impl ServingBinaryV3ProviderCodeSpool {
    fn new() -> io::Result<Self> {
        let base_dir = serving_binary_v3_spill_directory()?;
        let process_id = std::process::id();
        for attempt in 0..1000u32 {
            let path = base_dir.join(format!(
                "ptg2_v3_provider_codes_{process_id}_{:?}_{attempt}.pairs",
                thread::current().id()
            ));
            match OpenOptions::new().create_new(true).write(true).open(&path) {
                Ok(file) => {
                    return Ok(Self {
                        path,
                        writer: BufWriter::new(file),
                        row_count: 0,
                    });
                }
                Err(error) if error.kind() == io::ErrorKind::AlreadyExists => continue,
                Err(error) => return Err(error),
            }
        }
        Err(io::Error::new(
            io::ErrorKind::AlreadyExists,
            "unable to allocate PTG2 v3 provider-code spill file",
        ))
    }

    fn push(&mut self, provider_set_key: i32, code_key: i32) -> io::Result<()> {
        let mut pair = [0u8; PROVIDER_CODE_PAIR_RECORD_BYTES];
        pair[..4].copy_from_slice(&provider_set_key.to_be_bytes());
        pair[4..].copy_from_slice(&code_key.to_be_bytes());
        self.writer.write_all(&pair)?;
        self.row_count = self.row_count.saturating_add(1);
        Ok(())
    }

    fn emit_sorted_unique<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
        state: &mut ServingBinaryV3ProviderCodeState,
        chunk_bytes: usize,
    ) -> io::Result<ServingBinaryV3ProviderCodeSortSummary> {
        self.writer.flush()?;
        let spill_bytes = self
            .row_count
            .saturating_mul(PROVIDER_CODE_PAIR_RECORD_BYTES as u64);
        if spill_bytes <= chunk_bytes as u64 {
            let unique_pair_count = self.emit_in_memory(writer, target_format, state)?;
            return Ok(ServingBinaryV3ProviderCodeSortSummary {
                input_pair_count: self.row_count,
                unique_pair_count,
                spill_bytes,
                scratch_read_bytes: spill_bytes,
                scratch_written_bytes: spill_bytes,
                chunk_count: u64::from(self.row_count > 0),
                merge_pass_count: 0,
                maximum_merge_fan_in: 0,
                external_sort: false,
                ..ServingBinaryV3ProviderCodeSortSummary::default()
            });
        }

        let mut temporary_files = ManifestPairTemporaryFiles::default();
        let sorted_path = manifest_pair_temporary_path(&self.path, "provider-code-sorted", 0);
        let temporary_directory = self.path.parent().unwrap_or_else(|| Path::new("."));
        let records_per_chunk = (chunk_bytes / PROVIDER_CODE_PAIR_RECORD_BYTES).max(1);
        let stats = external_sort_provider_code_pairs(
            std::slice::from_ref(&self.path),
            &sorted_path,
            temporary_directory,
            records_per_chunk,
        )?;
        temporary_files.track(sorted_path.clone());
        if stats.input_records != self.row_count || stats.input_bytes != spill_bytes {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "provider-code external sort input accounting mismatch",
            ));
        }
        let mut sorted_reader = BufReader::new(File::open(&sorted_path)?);
        let mut unique_pair_count = 0u64;
        while let Some(pair) = read_provider_code_pair(&mut sorted_reader)? {
            emit_provider_code_pair(writer, target_format, state, pair)?;
            unique_pair_count = unique_pair_count.saturating_add(1);
        }
        if unique_pair_count != stats.unique_records {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "provider-code external sort output accounting mismatch",
            ));
        }
        let merge_pass_count = provider_code_merge_pass_count(stats.chunk_count);
        Ok(ServingBinaryV3ProviderCodeSortSummary {
            input_pair_count: self.row_count,
            unique_pair_count,
            spill_bytes,
            scratch_read_bytes: stats
                .input_bytes
                .saturating_add(stats.spill_bytes)
                .saturating_add(stats.output_bytes),
            scratch_written_bytes: spill_bytes
                .saturating_add(stats.spill_bytes)
                .saturating_add(stats.output_bytes),
            chunk_count: stats.chunk_count,
            merge_pass_count,
            maximum_merge_fan_in: usize::try_from(stats.chunk_count)
                .unwrap_or(usize::MAX)
                .min(SERVING_BINARY_V3_PROVIDER_CODE_MERGE_FAN_IN),
            external_sort: true,
            ..ServingBinaryV3ProviderCodeSortSummary::default()
        })
    }

    fn emit_in_memory<W: SharedBlockCopyWriter>(
        &self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
        state: &mut ServingBinaryV3ProviderCodeState,
    ) -> io::Result<u64> {
        let mut reader = BufReader::new(File::open(&self.path)?);
        let pair_capacity = usize::try_from(self.row_count).map_err(|_| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "provider-code pair count exceeds usize",
            )
        })?;
        let mut pairs = Vec::new();
        pairs.try_reserve_exact(pair_capacity).map_err(|error| {
            io::Error::new(
                io::ErrorKind::OutOfMemory,
                format!(
                    "unable to reserve {} bytes for provider-code sorting: {error}",
                    pair_capacity.saturating_mul(PROVIDER_CODE_PAIR_RECORD_BYTES)
                ),
            )
        })?;
        while let Some(pair) = read_provider_code_pair(&mut reader)? {
            pairs.push(pair);
        }
        pairs.sort_unstable();
        pairs.dedup();
        for pair in &pairs {
            emit_provider_code_pair(writer, target_format, state, *pair)?;
        }
        Ok(pairs.len() as u64)
    }
}

impl Drop for ServingBinaryV3ProviderCodeSpool {
    fn drop(&mut self) {
        let _ = std::fs::remove_file(&self.path);
    }
}

fn read_provider_code_pair<R: Read>(
    reader: &mut R,
) -> io::Result<Option<[u8; PROVIDER_CODE_PAIR_RECORD_BYTES]>> {
    let mut pair = [0u8; PROVIDER_CODE_PAIR_RECORD_BYTES];
    let mut offset = 0usize;
    while offset < pair.len() {
        let bytes_read = reader.read(&mut pair[offset..])?;
        if bytes_read == 0 {
            if offset == 0 {
                return Ok(None);
            }
            return Err(io::Error::new(
                io::ErrorKind::UnexpectedEof,
                "PTG2 v3 provider-code spool ended with a partial record",
            ));
        }
        offset += bytes_read;
    }
    Ok(Some(pair))
}

fn emit_provider_code_pair<W: SharedBlockCopyWriter>(
    writer: &mut W,
    target_format: ServingBinaryTargetCopyFormat,
    state: &mut ServingBinaryV3ProviderCodeState,
    pair: [u8; PROVIDER_CODE_PAIR_RECORD_BYTES],
) -> io::Result<()> {
    let provider_set_key = i32::from_be_bytes(pair[..4].try_into().map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "provider-code provider key is invalid",
        )
    })?);
    let code_key = i32::from_be_bytes(pair[4..].try_into().map_err(|_| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "provider-code code key is invalid",
        )
    })?);
    state.push(
        writer,
        target_format,
        i64::from(provider_set_key),
        i64::from(code_key),
    )
}

fn provider_code_bitmap_layout_bytes(
    provider_set_count: usize,
    code_count: usize,
) -> io::Result<(usize, usize)> {
    let words_per_provider = code_count.checked_add(63).ok_or_else(|| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            "provider-code bitmap code dimension overflows usize",
        )
    })? / 64;
    let total_words = provider_set_count
        .checked_mul(words_per_provider)
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "provider-code bitmap word count overflows usize",
            )
        })?;
    let total_bytes = total_words
        .checked_mul(std::mem::size_of::<u64>())
        .ok_or_else(|| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "provider-code bitmap byte count overflows usize",
            )
        })?;
    Ok((words_per_provider, total_bytes))
}

enum ServingBinaryV3ProviderCodeIndex {
    Bitmap {
        words: Vec<u64>,
        words_per_provider: usize,
        provider_set_count: usize,
        code_count: usize,
        input_pair_count: u64,
        unique_pair_count: u64,
        maximum_bytes: usize,
    },
    Spool {
        spool: ServingBinaryV3ProviderCodeSpool,
        bitmap_candidate_bytes: Option<usize>,
        bitmap_maximum_bytes: usize,
        bitmap_fallback_reason: &'static str,
    },
}

impl ServingBinaryV3ProviderCodeIndex {
    fn new(
        provider_set_count: Option<usize>,
        code_count: Option<usize>,
        bitmap_maximum_bytes: usize,
    ) -> io::Result<Self> {
        let (Some(provider_set_count), Some(code_count)) = (provider_set_count, code_count) else {
            return Ok(Self::Spool {
                spool: ServingBinaryV3ProviderCodeSpool::new()?,
                bitmap_candidate_bytes: None,
                bitmap_maximum_bytes,
                bitmap_fallback_reason: "dimensions_unavailable",
            });
        };
        let (words_per_provider, bitmap_candidate_bytes) =
            match provider_code_bitmap_layout_bytes(provider_set_count, code_count) {
                Ok(layout) => layout,
                Err(_) => {
                    return Ok(Self::Spool {
                        spool: ServingBinaryV3ProviderCodeSpool::new()?,
                        bitmap_candidate_bytes: None,
                        bitmap_maximum_bytes,
                        bitmap_fallback_reason: "matrix_size_overflow",
                    });
                }
            };
        if bitmap_candidate_bytes > bitmap_maximum_bytes {
            return Ok(Self::Spool {
                spool: ServingBinaryV3ProviderCodeSpool::new()?,
                bitmap_candidate_bytes: Some(bitmap_candidate_bytes),
                bitmap_maximum_bytes,
                bitmap_fallback_reason: "memory_cap_exceeded",
            });
        }
        let total_words = bitmap_candidate_bytes / std::mem::size_of::<u64>();
        let mut words = Vec::new();
        if words.try_reserve_exact(total_words).is_err() {
            return Ok(Self::Spool {
                spool: ServingBinaryV3ProviderCodeSpool::new()?,
                bitmap_candidate_bytes: Some(bitmap_candidate_bytes),
                bitmap_maximum_bytes,
                bitmap_fallback_reason: "allocation_failed",
            });
        }
        words.resize(total_words, 0);
        Ok(Self::Bitmap {
            words,
            words_per_provider,
            provider_set_count,
            code_count,
            input_pair_count: 0,
            unique_pair_count: 0,
            maximum_bytes: bitmap_maximum_bytes,
        })
    }

    fn push(&mut self, provider_set_key: i32, code_key: i32) -> io::Result<()> {
        match self {
            Self::Bitmap {
                words,
                words_per_provider,
                provider_set_count,
                code_count,
                input_pair_count,
                unique_pair_count,
                ..
            } => {
                let provider_index = usize::try_from(provider_set_key).map_err(|_| {
                    io::Error::new(
                        io::ErrorKind::InvalidData,
                        "provider_set_key cannot be negative",
                    )
                })?;
                let code_index = usize::try_from(code_key).map_err(|_| {
                    io::Error::new(io::ErrorKind::InvalidData, "code_key cannot be negative")
                })?;
                if provider_index >= *provider_set_count || code_index >= *code_count {
                    return Err(io::Error::new(
                        io::ErrorKind::InvalidData,
                        format!(
                            "provider/code pair ({provider_set_key}, {code_key}) is outside charged bitmap dimensions {} x {}",
                            provider_set_count, code_count,
                        ),
                    ));
                }
                let word_index = provider_index
                    .checked_mul(*words_per_provider)
                    .and_then(|offset| offset.checked_add(code_index / 64))
                    .ok_or_else(|| {
                        io::Error::new(
                            io::ErrorKind::InvalidData,
                            "provider-code bitmap index overflows usize",
                        )
                    })?;
                let bit = 1u64 << (code_index % 64);
                *input_pair_count = input_pair_count.saturating_add(1);
                if words[word_index] & bit == 0 {
                    words[word_index] |= bit;
                    *unique_pair_count = unique_pair_count.saturating_add(1);
                }
                Ok(())
            }
            Self::Spool { spool, .. } => spool.push(provider_set_key, code_key),
        }
    }

    fn emit_sorted_unique<W: SharedBlockCopyWriter>(
        &mut self,
        writer: &mut W,
        target_format: ServingBinaryTargetCopyFormat,
        state: &mut ServingBinaryV3ProviderCodeState,
        chunk_bytes: usize,
    ) -> io::Result<ServingBinaryV3ProviderCodeSortSummary> {
        match self {
            Self::Bitmap {
                words,
                words_per_provider,
                provider_set_count,
                code_count,
                input_pair_count,
                unique_pair_count,
                maximum_bytes,
            } => {
                let mut emitted_pairs = 0u64;
                for provider_index in 0..*provider_set_count {
                    let word_start = provider_index * *words_per_provider;
                    for (relative_word, stored_word) in words
                        [word_start..word_start + *words_per_provider]
                        .iter()
                        .copied()
                        .enumerate()
                    {
                        let mut pending_bits = stored_word;
                        while pending_bits != 0 {
                            let bit_index = pending_bits.trailing_zeros() as usize;
                            let code_index = relative_word * 64 + bit_index;
                            if code_index >= *code_count {
                                return Err(io::Error::new(
                                    io::ErrorKind::InvalidData,
                                    "provider-code bitmap contains a bit outside the code dimension",
                                ));
                            }
                            state.push(
                                writer,
                                target_format,
                                provider_index as i64,
                                code_index as i64,
                            )?;
                            emitted_pairs = emitted_pairs.saturating_add(1);
                            pending_bits &= pending_bits - 1;
                        }
                    }
                }
                if emitted_pairs != *unique_pair_count {
                    return Err(io::Error::new(
                        io::ErrorKind::InvalidData,
                        "provider-code bitmap emission count mismatch",
                    ));
                }
                Ok(ServingBinaryV3ProviderCodeSortSummary {
                    input_pair_count: *input_pair_count,
                    unique_pair_count: *unique_pair_count,
                    index_mode: "provider_major_bitmap_v1",
                    bitmap_candidate_bytes: Some(words.len() as u64 * 8),
                    bitmap_charged_bytes: words.len() as u64 * 8,
                    bitmap_maximum_bytes: *maximum_bytes as u64,
                    ..ServingBinaryV3ProviderCodeSortSummary::default()
                })
            }
            Self::Spool {
                spool,
                bitmap_candidate_bytes,
                bitmap_maximum_bytes,
                bitmap_fallback_reason,
            } => {
                let mut summary =
                    spool.emit_sorted_unique(writer, target_format, state, chunk_bytes)?;
                summary.index_mode = "pair_spool_sort_v1";
                summary.bitmap_candidate_bytes = bitmap_candidate_bytes.map(|bytes| bytes as u64);
                summary.bitmap_maximum_bytes = *bitmap_maximum_bytes as u64;
                summary.bitmap_fallback_reason = Some(*bitmap_fallback_reason);
                Ok(summary)
            }
        }
    }
}

fn provider_code_merge_pass_count(mut chunk_count: u64) -> usize {
    if chunk_count == 0 {
        return 0;
    }
    let mut pass_count = 1usize;
    while chunk_count >= SERVING_BINARY_V3_PROVIDER_CODE_MERGE_FAN_IN as u64 {
        chunk_count = chunk_count.div_ceil(SERVING_BINARY_V3_PROVIDER_CODE_MERGE_FAN_IN as u64);
        pass_count = pass_count.saturating_add(1);
    }
    pass_count
}

#[cfg(test)]
struct PgBinaryAssignedV3RowSource<'a, R> {
    reader: &'a mut R,
    field_count: i16,
    source_field_present: bool,
}

#[cfg(test)]
impl<'a, R: Read> PgBinaryAssignedV3RowSource<'a, R> {
    fn new(reader: &'a mut R, source_field_present: bool) -> io::Result<Self> {
        read_pg_binary_copy_header(reader)?;
        Ok(Self {
            reader,
            field_count: if source_field_present { 5 } else { 4 },
            source_field_present,
        })
    }
}

#[cfg(test)]
impl<R: Read> AssignedV3RowSource for PgBinaryAssignedV3RowSource<'_, R> {
    fn next_row(&mut self) -> io::Result<Option<AssignedV3Row>> {
        let Some(fields) =
            read_pg_binary_copy_row(self.reader, self.field_count, "PTG2 v3 assigned by-code")?
        else {
            return Ok(None);
        };
        let code_key = pg_binary_nonnegative_i32(
            required_pg_binary_field(&fields, 0, "code_key")?,
            "code_key",
        )?;
        let provider_set_key = pg_binary_nonnegative_i32(
            required_pg_binary_field(&fields, 1, "provider_set_key")?,
            "provider_set_key",
        )?;
        let provider_count = pg_binary_u64(
            required_pg_binary_field(&fields, 2, "provider_count")?,
            "provider_count",
        )?;
        let price_key = u32::try_from(pg_binary_nonnegative_i64(
            required_pg_binary_field(&fields, 3, "price_key")?,
            "price_key",
        )?)
        .map_err(|_| {
            io::Error::new(
                io::ErrorKind::InvalidData,
                "PTG2 v3 assigned price_key exceeds u32",
            )
        })?;
        let source_key = if self.source_field_present {
            u32::try_from(pg_binary_nonnegative_i64(
                required_pg_binary_field(&fields, 4, "source_key")?,
                "source_key",
            )?)
            .map_err(|_| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    "PTG2 v3 assigned source_key exceeds u32",
                )
            })?
        } else {
            0
        };
        Ok(Some(AssignedV3Row {
            code_key,
            provider_set_key,
            provider_count,
            price_key,
            source_key,
        }))
    }

    fn source_copy_format(&self) -> &'static str {
        "postgres_binary"
    }
}

#[cfg(test)]
